const questionsFr: Question[] = [
  // Principes fondamentaux
  { q: "En harmonisation modale, quel est l'objectif principal des accords ?", opts: ["Créer tension et résolution (SD→D→T)", "Maintenir et colorer le mode sans résolution obligatoire", "Toujours finir sur V7→I", "Utiliser les 7 accords diatoniques de manière égale"], a: 1, fb: "En modal, les accords doivent préserver la couleur du mode — pas créer de tension tonale. L'oscillation entre Im et un accord caractéristique suffit ; une résolution V7→I briserait l'identité modale." },
  { q: "Pourquoi faut-il éviter V7→I dans un contexte modal ?", opts: ["V7 est trop dissonant", "V7 introduit la sensible absente du mode, créant une résolution tonale qui efface la couleur modale", "V7 n'existe pas en musique modale", "V7 est réservé aux modes majeurs"], a: 1, fb: "La sensible dans V7 crée une tension irrésistible vers I — c'est le moteur tonal. En modal, on veut éviter cette attraction pour maintenir la couleur flottante du mode." },
  { q: "Quelle est la différence fondamentale entre une harmonisation tonale et modale ?", opts: ["La tonale utilise plus d'accords", "La tonale organise les accords en hiérarchie tension/résolution ; la modale maintient une couleur stable", "La modale n'utilise que des accords mineurs", "La tonale est plus moderne"], a: 1, fb: "Tonal = hiérarchie fonctionnelle (T, SD, D) avec résolution obligatoire. Modal = couleur harmonique stable — les accords oscillent autour de la tonique sans l'appeler de manière impérative." },
  { q: "Comment identifier l'accord caractéristique d'un mode pour l'harmonisation ?", opts: ["C'est toujours l'accord IV", "C'est l'accord construit sur la note distinctive du mode par rapport à la gamme majeure ou mineure standard", "C'est toujours l'accord ♭VII", "C'est le premier accord diatonique"], a: 1, fb: "L'accord caractéristique met en valeur la note distinctive du mode. En dorien : IV majeur (6te majeure). En phrygien : ♭II (2de bémolisée). En lydien : II majeur (#4). En mixolydien : ♭VII (7te mineure)." },
  { q: "Laquelle de ces progressions est modale (pas tonale) ?", opts: ["I – IV – V7 – I", "IIm – V7 – Imaj7", "Im – IV – Im – IV (dorien)", "I – VI – II – V"], a: 2, fb: "Im – IV – Im – IV (D dorien : Dm – G – Dm – G) est une progression modale — elle oscille sans résolution V7→I. Les 3 autres sont des progressions tonales classiques avec un V7 actif vers I." },
  { q: "Qu'est-ce qui maintient la couleur modale dans une harmonisation ?", opts: ["Jouer toujours en mineur", "Utiliser régulièrement l'accord caractéristique du mode et éviter V7→I", "Éviter toute dissonance", "Rester sur un seul accord"], a: 1, fb: "La couleur modale est maintenue par deux éléments : l'utilisation de l'accord caractéristique (qui contient la note distinctive) et l'évitement de V7→I (qui créerait une résolution tonale)." },
  { q: "Comment la musique modale sonne-t-elle comparée à la musique tonale ?", opts: ["La modale 'arrive quelque part' comme la tonale", "La modale 'reste quelque part' — elle flotte et colore plutôt qu'elle ne progresse", "La modale est toujours plus rapide", "La modale utilise plus de dissonances"], a: 1, fb: "La musique tonale crée un sentiment de direction et d'arrivée (tension → résolution). La musique modale crée un sentiment de suspension, de couleur stable — elle 'est' quelque part plutôt qu'elle n'y 'arrive'." },
  { q: "En modal, que remplace fonctionnellement l'accord caractéristique du mode ?", opts: ["L'accord de sous-dominante", "La dominante V7 — il apporte de l'intérêt harmonique sans créer de résolution tonale", "La tonique", "L'accord de sixte napolitaine"], a: 1, fb: "L'accord caractéristique (IV en dorien, ♭II en phrygien…) est le point d'intérêt harmonique du mode — il évite la monotonie d'un accord unique, mais sans l'attraction directionnelle de V7." },

  // Dorien
  { q: "Quelle progression caractérise l'harmonisation en mode dorien ?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 1, fb: "Im – IV en dorien (ex. Dm – G en D dorien) est la progression modale fondamentale. IV est majeur grâce à la 6te majeure — c'est la couleur jazz-modal de So What de Miles Davis." },
  { q: "En D dorien, quel accord est IV et pourquoi est-il caractéristique ?", opts: ["Gm — il rappelle le mineur naturel", "G majeur — la 6te majeure (B naturel) le rend majeur", "G7 — il crée de la tension", "Gdim — il est instable"], a: 1, fb: "En D dorien : D E F G A B C. Sur G : G B D = G majeur. Le B naturel (6te majeure) rend cet accord majeur. En D mineur naturel, IV serait Gm — c'est cette différence qui fait la couleur dorienne." },
  { q: "Quel accord faut-il éviter en harmonisation dorienne ?", opts: ["IV majeur (G en D dorien)", "V7 (A7 en D dorien)", "♭III (F en D dorien)", "♭VII (C en D dorien)"], a: 1, fb: "A7 (V7 en D dorien) introduit C# — la sensible que le dorien n'a pas (C naturel). Ce C# crée une attraction tonale vers Dm qui brise la couleur modale et transforme le dorien en mineur harmonique." },
  { q: "Quelle pièce de Miles Davis est l'exemple modal dorien par excellence ?", opts: ["Kind of Blue — All Blues", "So What (D dorien)", "Round Midnight", "Autumn Leaves"], a: 1, fb: "So What (1959) est entièrement en D dorien. Miles Davis et Bill Evans construisent l'harmonie sur Dm7–G (Im–IV), sans jamais appeler de résolution tonale — c'est l'archétype du jazz modal." },
  { q: "En harmonisation dorienne, Im – IV crée :", opts: ["Une tension qui demande résolution", "Une oscillation colorée sans résolution", "Une cadence parfaite", "Un mouvement de sous-dominante vers dominante"], a: 1, fb: "Im – IV en dorien (Dm – G) oscille entre deux accords sans hiérarchie fonctionnelle. Pas de tension qui appelle résolution — c'est une couleur qui se maintient, flotte, respire." },
  { q: "En G dorien, quel accord est IV ?", opts: ["Cm (C mineur)", "C majeur", "Cdim", "C7"], a: 1, fb: "G dorien : G A Bb C D E F. Sur C : C E G = C majeur. La 6te majeure du dorien (E naturel au lieu de Eb) rend cet accord IV majeur — la marque harmonique du mode dorien." },
  { q: "La Bossa Nova utilise souvent le dorien car :", opts: ["Le dorien est uniquement brésilien", "La 6te majeure du dorien crée une couleur sophistiquée mi-sombre mi-lumineuse, parfaite pour la saudade", "Le dorien est le plus simple des modes", "La Bossa Nova évite les accords majeurs"], a: 1, fb: "La saudade brésilienne — mélancolie douce et lumineuse — trouve dans le dorien son expression harmonique parfaite. La 6te majeure empêche IV d'être sombre (Gm) — il reste lumineux (G), créant l'équilibre entre ombre et lumière." },

  // Phrygien
  { q: "Quelle est la cadence caractéristique du mode phrygien ?", opts: ["V7 – I", "IV – I", "♭II – Im (cadence phrygienne)", "♭VII – I"], a: 2, fb: "La cadence phrygienne ♭II→Im (ex. F→Em en E phrygien) est l'ADN harmonique du flamenco. Le mouvement descendant par demi-ton crée une tension unique différente de V7→I." },
  { q: "En E phrygien, quel accord est ♭II ?", opts: ["D majeur", "F majeur", "Eb majeur", "B majeur"], a: 1, fb: "E phrygien : E F G A B C D. Le ♭II est construit sur F : F A C = F majeur. La 2de bémolisée du phrygien (F au lieu de F#) crée cet accord très caractéristique." },
  { q: "Pourquoi le mouvement F→Em (en E phrygien) est-il si expressif ?", opts: ["F est une quarte de Em", "C'est un mouvement descendant par demi-ton — le plus serré de tous les intervalles", "F est la dominante de Em", "C'est un triton"], a: 1, fb: "F→E est un demi-ton descendant — l'intervalle le plus petit et le plus tendu. Ce mouvement ♭II→Im crée une attraction puissante par proximité chromatique, très différente de la résolution tonale V7→I." },
  { q: "Quel genre musical utilise principalement la cadence phrygienne ?", opts: ["Blues américain", "Jazz modal", "Flamenco espagnol", "Gospel"], a: 2, fb: "Le flamenco espagnol est fondé sur la cadence phrygienne ♭II→Im et ses variations. La couleur sombre et méditerranéenne du phrygien — avec sa 2de bémolisée — est l'identité sonore de la musique andalouse." },
  { q: "En harmonisation phrygienne, quel accord faut-il éviter ?", opts: ["♭II (F en E phrygien)", "Im (Em)", "V7 (B7 en E phrygien)", "♭VII (D en E phrygien)"], a: 2, fb: "B7 (V7 en E phrygien) introduit D# — une sensible étrangère au phrygien (D naturel). Ce D# crée une résolution tonale vers Em, effaçant la couleur phrygienne." },
  { q: "En A phrygien, quel accord est ♭II ?", opts: ["G majeur", "Bb majeur", "B majeur", "Ab majeur"], a: 1, fb: "A phrygien : A Bb C D E F G. Le ♭II est construit sur Bb : Bb D F = Bb majeur. La 2de bémolisée (Bb au lieu de B) crée cet accord caractéristique du phrygien." },
  { q: "La couleur 'sombre et méditerranéenne' est associée à quel mode ?", opts: ["Dorien", "Lydien", "Phrygien", "Éolien"], a: 2, fb: "Le phrygien est le mode de la méditerranée — sa 2de bémolisée et la cadence ♭II→Im créent une couleur sombre, intense, dramatique. C'est l'identité sonore du flamenco et de la musique espagnole." },

  // Lydien
  { q: "Quelle progression caractérise l'harmonisation en mode lydien ?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – II – I", "I – ♭VII – IV – I"], a: 2, fb: "I – II en lydien (ex. F – G en F lydien) est la progression caractéristique. Le II est majeur grâce au #4 — un mouvement de seconde montante majeur–majeur impossible en gamme majeure standard (où II est mineur)." },
  { q: "Pourquoi l'accord II est-il majeur en mode lydien ?", opts: ["Car le lydien est un mode mineur", "Car le #4 (4te augmentée) du lydien est dans l'accord II", "Car II est toujours majeur en modal", "Car le lydien est issu du IVe degré"], a: 1, fb: "En F lydien : F G A B C D E. Sur G (II) : G B D = G majeur. Le B naturel (#4 du lydien) est la tierce de G — il rend l'accord II majeur. En F majeur standard, II serait Gm (avec Bb)." },
  { q: "Quel compositeur de musiques de films utilise abondamment le lydien pour évoquer le merveilleux ?", opts: ["Ennio Morricone", "John Williams", "Hans Zimmer", "Bernard Herrmann"], a: 1, fb: "John Williams utilise le lydien dans E.T., Superman et ses musiques magiques. Le #4 crée une couleur lumineuse et onirique — la 4te augmentée évite la stabilité parfaite de la gamme majeure et fait 'flotter' la musique." },
  { q: "En F lydien, quel accord faut-il éviter pour préserver la couleur ?", opts: ["G majeur (II)", "Bb (IV de F majeur standard)", "Am (IIIm)", "C (V)"], a: 1, fb: "Bb réintroduit exactement la note que le lydien remplace par B naturel (#4). Jouer Bb efface instantanément la couleur lydienne et fait entendre une gamme majeure standard." },
  { q: "En C lydien, quel accord est II ?", opts: ["Dm", "D majeur", "Ddim", "D7"], a: 1, fb: "C lydien : C D E F# G A B. Sur D : D F# A = D majeur. Le F# (#4 du lydien) est la tierce de D — il rend l'accord II majeur et révèle le mode à l'oreille." },
  { q: "La couleur 'lumineuse et onirique' est associée à quel mode ?", opts: ["Éolien", "Phrygien", "Mixolydien", "Lydien"], a: 3, fb: "Le lydien avec son #4 crée une couleur lumineuse et onirique. La 4te augmentée évite la stabilité parfaite de la gamme majeure — elle flotte, elle brille. C'est le mode de l'émerveillement et de la magie." },
  { q: "Le thème principal des Simpsons commence par un :", opts: ["Saut de phrygien (♭2)", "Triton ascendant lydien (fondamentale vers #4)", "Accord de dominante", "Mouvement éolien (♭VII)"], a: 1, fb: "Le thème des Simpsons commence par un saut ascendant vers le #4 lydien — le triton F→B en F lydien. C'est ce #4 légèrement bizarre qui crée cette couleur si reconnaissable." },

  // Mixolydien
  { q: "Quelle progression est typique du mode mixolydien ?", opts: ["Im – IV – Im", "Im – ♭VI – ♭VII – Im", "I – ♭VII – IV – I", "I – II – I"], a: 2, fb: "I – ♭VII – IV – I (ex. G – F – C – G en G mixolydien) est la progression rock/blues par excellence. Le ♭VII (F) crée un mouvement de retour sans résolution de sensible." },
  { q: "En G mixolydien, quel accord est ♭VII ?", opts: ["F# majeur", "F mineur", "F majeur", "Fdim"], a: 2, fb: "G mixolydien : G A B C D E F. Le ♭VII est construit sur F : F A C = F majeur. La 7te mineure (F au lieu de F#) rend cet accord majeur — c'est la marque harmonique du mixolydien." },
  { q: "Pourquoi évite-t-on V7 en harmonisation mixolydienne ?", opts: ["V7 est trop simple", "V7 introduit la sensible (F# en G mixolydien) absente du mode, créant une résolution vers G", "V7 crée une quinte parallèle", "V7 change le mode en lydien"], a: 1, fb: "En G mixolydien, F est ♭7 (note caractéristique). D7 (V7) introduit F# — la sensible qui n'existe pas dans le mode. Ce F# crée une tension vers G (résolution tonale) qui brise la couleur cyclique du mixolydien." },
  { q: "Quel style musical est harmoniquement basé sur le mode mixolydien ?", opts: ["Musique baroque", "Flamenco espagnol", "Blues et rock", "Musique romantique"], a: 2, fb: "Le blues et le rock utilisent principalement le mixolydien. L'accord I7 du blues (avec 7te mineure) est l'accord du mixolydien. La progression I7–IV7–V7 du blues est fondamentalement mixolydienne." },
  { q: "Norwegian Wood des Beatles est en quel mode ?", opts: ["Dorien", "Phrygien", "Éolien", "Mixolydien"], a: 3, fb: "Norwegian Wood (1965) est en E mixolydien. La 7te mineure (D naturel au lieu de D#) dans la mélodie et l'harmonie donne cette couleur modale caractéristique — majeur mais non résolu." },
  { q: "En D mixolydien, quel accord est ♭VII ?", opts: ["C# majeur", "C mineur", "C majeur", "Cdim"], a: 2, fb: "D mixolydien : D E F# G A B C. Sur C : C E G = C majeur. La 7te mineure (C au lieu de C#) est la note caractéristique du mixolydien — et cet accord ♭VII majeur en est la signature harmonique." },
  { q: "La couleur 'énergique et cyclique sans résolution' est associée à quel mode ?", opts: ["Ionien", "Dorien", "Éolien", "Mixolydien"], a: 3, fb: "Le mixolydien crée une énergie perpétuelle — la progression I–♭VII–IV–I tourne sans jamais vraiment 'arriver'. La 7te mineure empêche la résolution vers I tout en gardant la couleur majeure. C'est l'essence du blues et du rock." },

  // Éolien
  { q: "Quelle progression est typique du mode éolien ?", opts: ["Im – IV – Im", "Im – ♭II – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 3, fb: "Im – ♭VI – ♭VII – Im (ex. Am – F – G – Am en A éolien) est la progression mineure naturelle la plus répandue en pop et rock. Elle oscille sans sensible, créant une mélancolie douce et naturelle." },
  { q: "En A éolien, pourquoi ♭VII est-il G majeur ?", opts: ["Car G est la quinte de C", "Car en A éolien (A B C D E F G), l'accord sur G est G B D = G majeur", "Car G est toujours majeur en mineur", "Car G est la tonique relative"], a: 1, fb: "A éolien : A B C D E F G. Sur G (♭VII) : G B D = G majeur. Le B naturel dans G donne un accord majeur lumineux sur le ♭VII — c'est lui qui empêche la couleur d'être trop sombre." },
  { q: "Comment l'éolien se distingue-t-il harmoniquement du mineur harmonique ?", opts: ["L'éolien a une tierce majeure", "L'éolien n'a pas de sensible — son V est Vm (mineur), pas V7", "L'éolien n'a pas de IVe degré", "L'éolien utilise l'accord napolitain"], a: 1, fb: "En éolien, V = Em (mineur, sans sensible). En mineur harmonique, V = E7 (avec G# sensible). Cette sensible crée la résolution tonale. L'éolien évite cette tension — plus naturel, moins dirigé." },
  { q: "La progression Am – F – G – Am est typiquement :", opts: ["Tonale (mineur harmonique)", "Modale (éolien naturel)", "Tonale (majeur)", "Pentatonique"], a: 1, fb: "Am – F – G – Am est purement éolienne — sans E7 (V7). G (♭VII) et F (♭VI) sont caractéristiques du mineur naturel/éolien. C'est la progression de House of the Rising Sun, Losing My Religion..." },
  { q: "En A éolien, quel problème pose E7 (V7) ?", opts: ["Il est trop grave", "Il introduit G# — la sensible absente de l'éolien — créant une résolution tonale vers Am", "Il crée une quinte parallèle", "Il force le passage en lydien"], a: 1, fb: "E7 contient G# — la sensible que l'éolien n'a pas (G naturel). Ce G# appelle impérativement la résolution vers A, transformant le mode en mineur harmonique et brisant la mélancolie naturelle de l'éolien." },
  { q: "En E éolien, quel accord est ♭VII ?", opts: ["D# majeur", "D mineur", "D majeur", "Ddim"], a: 2, fb: "E éolien : E F# G A B C D. Sur D : D F# A = D majeur. Le D naturel (♭7) rend l'accord ♭VII majeur — sa présence caractérise harmoniquement le mode éolien et distingue sa couleur du mineur harmonique." },
  { q: "Stairway to Heaven de Led Zeppelin utilise principalement :", opts: ["Le mode lydien", "Le mode mixolydien", "Le mode éolien (mineur naturel)", "Le mode phrygien"], a: 2, fb: "Stairway to Heaven s'appuie sur A mineur naturel (A éolien) — la progression Am – G – F caractéristique. La mélancolie introspective du mineur naturel sans sensible est typiquement éolienne." },

  // Applications comparatives
  { q: "Un accord IV majeur dans un contexte mineur indique probablement quel mode ?", opts: ["Mineur harmonique", "Mode dorien", "Mode phrygien", "Mode locrien"], a: 1, fb: "IV majeur dans un contexte mineur est la signature harmonique du dorien. En mineur naturel (éolien), IV serait mineur. La présence d'un IV majeur (ex. G en D mineur) signale la 6te majeure dorienne." },
  { q: "Un accord ♭II dans un contexte mineur indique probablement quel mode ?", opts: ["Mode dorien", "Mineur harmonique", "Mode phrygien", "Mode éolien"], a: 2, fb: "♭II dans un contexte mineur est la signature du phrygien. L'accord bâti sur la 2de bémolisée (ex. F en E phrygien) est unique à ce mode — aucun autre mode mineur ne le possède naturellement." },
  { q: "Un accord ♭VII majeur dans un contexte majeur indique probablement quel mode ?", opts: ["Mode lydien", "Mode ionien", "Mode mixolydien", "Mode dorien"], a: 2, fb: "♭VII majeur dans un contexte majeur est la signature du mixolydien. En gamme majeure standard, ♭VII n'existe pas (le VIIe degré est diminué). La présence de ♭VII majeur (ex. F en G majeur) signale la 7te mineure mixolydienne." },
  { q: "Quelle est la différence entre Im–IV (dorien) et Im–Vm (éolien) ?", opts: ["Im–IV est plus fort dynamiquement", "Im–IV utilise IV majeur (dorien, 6te majeure) ; Im–Vm utilise V mineur (éolien, 6te mineure)", "Im–Vm est une cadence parfaite", "Il n'y a pas de différence"], a: 1, fb: "La différence est la 6te du mode. Dorien : 6te majeure → IV est majeur (G en D dorien). Éolien : 6te mineure → Vm est mineur (Em en A éolien). Ces deux accords créent une couleur radicalement différente." },
  { q: "Quelle progression est la plus tonale parmi ces options ?", opts: ["Dm – G – Dm (Im–IV dorien)", "Em – F – Em (♭II phrygien)", "Am – Dm – E7 – Am", "G – F – C – G (mixolydien)"], a: 2, fb: "Am – Dm – E7 – Am contient E7 (V7) qui introduit G# (sensible) et résout tonalement vers Am — c'est du mineur harmonique, pas du modal. Les 3 autres évitent V7→I et maintiennent une couleur modale." },
  { q: "Pour harmoniser une mélodie rock avec un riff G – F – C – G, le mode est :", opts: ["Ionien (G majeur)", "Dorien", "Mixolydien (G mixolydien)", "Lydien"], a: 2, fb: "G – F – C – G = I – ♭VII – IV – I en G mixolydien. Le F (♭VII) n'existe pas en G majeur standard (F# y est naturel). La présence de F naturel confirme le G mixolydien — mode du blues et du rock." },
  { q: "Pour harmoniser une mélodie de flamenco, quel mode choisir ?", opts: ["Dorien (Im–IV)", "Phrygien (Im–♭II)", "Mixolydien (I–♭VII)", "Éolien (Im–♭VI–♭VII)"], a: 1, fb: "Le flamenco utilise le mode phrygien. La cadence ♭II→Im (ex. F→Em en E phrygien) est l'ADN harmonique du flamenco — la couleur sombre et méditerranéenne vient directement de la 2de bémolisée." },
  { q: "So What de Miles Davis (1959) est harmonisé avec :", opts: ["Des accords phrygiens", "Des accords doriens (Dm7–G)", "Des accords mixolydiens", "Des accords lydiens"], a: 1, fb: "So What est en D dorien. Miles Davis utilise l'oscillation Dm7 – G (Im – IV en dorien) — pas de V7→I. La couleur jazz-modal vient de ce IV majeur (G) dans un contexte mineur (Dm)." },
  { q: "Une harmonisation modale typique :", opts: ["Contient toujours V7→I", "Évite V7→I et utilise l'accord caractéristique du mode de manière répétée", "N'utilise que des accords mineurs", "Module vers la relative majeure"], a: 1, fb: "Une harmonisation modale repose sur : éviter V7→I (résolution tonale) et utiliser régulièrement l'accord caractéristique (IV en dorien, ♭II en phrygien, etc.) qui révèle la couleur du mode." },

  // Accords caractéristiques
  { q: "Quel est l'accord caractéristique du mode éolien ?", opts: ["IV majeur", "♭II majeur", "♭VII majeur (sans sensible)", "II majeur"], a: 2, fb: "♭VII majeur distingue harmoniquement l'éolien du mineur harmonique. En A éolien : G majeur (♭VII). L'absence de sensible (G au lieu de G#) est la marque de l'éolien naturel." },
  { q: "Quel accord est unique au mode lydien parmi les modes majeurs ?", opts: ["IV majeur", "V dominant", "II majeur", "♭VII majeur"], a: 2, fb: "II majeur n'existe qu'en lydien parmi les modes de la gamme majeure. En ionien et mixolydien, II est mineur. En lydien, le #4 rend II majeur — c'est l'accord qui 'trahit' le mode à l'oreille." },
  { q: "En mode phrygien, quel accord n'appartient PAS au mode ?", opts: ["Im (Em en E phrygien)", "♭II (F en E phrygien)", "V7 (B7 en E phrygien)", "♭VII (D en E phrygien)"], a: 2, fb: "B7 contient D# — la sensible absente du phrygien (D naturel). Cet accord est 'étranger' au mode : il brise la couleur phrygienne en créant une attraction tonale vers Em." },
  { q: "Comparer dorien et éolien : quelle est l'unique note différente ?", opts: ["La 3ce (majeure vs mineure)", "La 6te (majeure en dorien, mineure en éolien)", "La 5te (juste vs diminuée)", "La 2de (majeure vs bémolisée)"], a: 1, fb: "Dorien et éolien ont les mêmes degrés sauf la 6te : dorien a une 6te majeure (B en D dorien), éolien a une 6te mineure (Bb en D éolien). Cette seule note change l'accord IV de Gm à G majeur — toute la couleur en découle." },
  { q: "Comparer mixolydien et ionien : quelle est l'unique note différente ?", opts: ["La 3ce (majeure vs mineure)", "La 4te (juste vs augmentée)", "La 7te (majeure en ionien, mineure en mixolydien)", "La 5te (juste vs diminuée)"], a: 2, fb: "Mixolydien = ionien avec ♭7. En G majeur : F# devient F naturel. Cette seule altération transforme l'accord VII de F#dim en F majeur (♭VII) — et crée la couleur blues/rock sans résolution." },

  // Questions avancées
  { q: "Pourquoi la musique modale semble-t-elle parfois 'flotter' ou 'tourner en rond' ?", opts: ["Car les musiciens jouent mal les transitions", "Car il n'y a pas de résolution tonale obligatoire — les accords oscillent plutôt qu'ils ne progressent", "Car le tempo est trop lent", "Car les modes n'ont pas de tonique"], a: 1, fb: "La musique tonale crée direction et arrivée (tension → résolution). La musique modale crée suspension, couleur stable — les accords oscillent autour de la tonique sans l'appeler de manière impérative. C'est voulu." },
  { q: "Les progressions d'accords parallèles de Debussy sont-elles tonales ou modales ?", opts: ["Tonales — technique classique", "Modales — les accords colorent le mode sans rôle fonctionnel", "Atonales — pas de tonalité", "Pentatoniques"], a: 1, fb: "Les accords parallèles de Debussy sont une technique modale : les accords ne créent pas de tension fonctionnelle (SD→D→T), ils se déplacent comme des blocs de couleur — libération des contraintes du contrepoint tonal." },
  { q: "Dans quelle œuvre de Debussy l'influence modale est-elle la plus évidente ?", opts: ["Clair de Lune (mineur classique)", "La Cathédrale engloutie (modes médiévaux et accords parallèles)", "Nocturnes de Chopin (romantique)", "Symphonie de Franck"], a: 1, fb: "La Cathédrale engloutie (1910) utilise des modes médiévaux (lydien, mixolydien) et des accords parallèles pour évoquer la cathédrale sous les eaux — l'exemple parfait de l'harmonie modale impressionniste." },
  { q: "Quel élément harmonique permet d'identifier un mode à l'oreille ?", opts: ["La vitesse de la progression", "L'accord caractéristique — l'accord qui contient la note distinctive du mode", "Le nombre d'accords utilisés", "Le registre de la mélodie"], a: 1, fb: "L'accord caractéristique 'révèle' le mode. Dorien : IV majeur. Phrygien : ♭II. Lydien : II majeur. Mixolydien : ♭VII. Éolien : ♭VII sans sensible. C'est lui qu'on entend comme 'la couleur' du mode." },
  { q: "La progression I7 – IV7 – V7 du blues sur 12 mesures est :", opts: ["Tonale (mineur harmonique)", "Modale (mixolydienne)", "Atonale", "Modale (dorienne)"], a: 1, fb: "Le blues est fondamentalement mixolydien : chaque accord (I, IV, V) a une 7te mineure, aucun ne résout vers l'autre de manière tonale. C'est un système circulaire qui tourne, pas une progression vers une résolution finale." },
  { q: "En modal, une 'pédale' est :", opts: ["Un accord très grave", "Une note tenue à la basse sous laquelle la mélodie change de couleur", "Un accord diminué", "Un accord de dominante"], a: 1, fb: "Une pédale (note ou accord tenu) maintient une couleur fixe pendant que la mélodie explore le mode. C'est une technique modale classique — l'accord ne change pas fonctionnellement, il établit un centre coloristique stable." },
  { q: "Oye Como Va de Santana est en quel mode ?", opts: ["Phrygien", "Lydien", "Dorien", "Éolien"], a: 2, fb: "Oye Como Va est en A dorien. La progression Am–D (Im–IV) est typiquement dorienne — l'accord IV (D majeur) révèle la 6te majeure (F#) du mode. Carlos Santana est l'un des maîtres du son dorien." },
  { q: "Quelle est la signature harmonique du dorien par rapport au phrygien ?", opts: ["Le dorien a ♭II ; le phrygien a IV majeur", "Le dorien a IV majeur ; le phrygien a ♭II", "Les deux ont le même accord caractéristique", "Le dorien a ♭VII ; le phrygien a #IV"], a: 1, fb: "Dorien : l'accord caractéristique est IV majeur (grâce à la 6te majeure). Phrygien : l'accord caractéristique est ♭II (grâce à la 2de bémolisée). Ces deux accords 'trahissent' immédiatement le mode à l'oreille." },
  { q: "Dans quelle harmonisation Am – G – F – E7 y a-t-il une 'sortie' du mode éolien ?", opts: ["Am – G", "G – F", "F – E7", "E7 est la sortie : V7 avec sensible G# absente de l'éolien"], a: 3, fb: "E7 (V7) introduit G# — la sensible absente de A éolien (G naturel). Cet accord brise la couleur modale éolienne et transforme temporairement le contexte en mineur harmonique, créant une résolution tonale vers Am." },
  { q: "Parmi ces descriptions, laquelle correspond à une harmonisation dorienne ?", opts: ["Sombre et tendue, avec V7→Im", "Mi-mineure mi-lumineuse, avec IV majeur caractéristique et sans V7→I", "Lumineuse et flottante, avec II majeur", "Cyclique et blues, avec ♭VII–IV"], a: 1, fb: "Le dorien est mi-mineur (Im, 3ce mineure) mi-lumineux (IV majeur, 6te majeure). Cette ambiguïté est sa couleur — ni trop sombre ni trop clair. L'absence de V7→I maintient la flottaison modale." },
  { q: "Quels modes sont dits 'majeurs' (tierce majeure) ?", opts: ["Ionien, Lydien, Mixolydien", "Dorien, Éolien, Phrygien", "Ionien, Dorien, Phrygien", "Lydien, Éolien, Locrien"], a: 0, fb: "Ionien (I), Lydien (IV) et Mixolydien (V) ont une tierce majeure — ce sont les modes 'majeurs'. Les 4 autres (Dorien, Phrygien, Éolien, Locrien) ont une tierce mineure." },
  { q: "Quel mode est le plus difficile à utiliser comme centre tonal stable ?", opts: ["Dorien", "Phrygien", "Éolien", "Locrien"], a: 3, fb: "Le locrien a une tonique diminuée — la quinte entre la fondamentale et la quinte est bémolisée (ex. B–F en B locrien, un triton). Cet accord de tonique est si instable qu'il est presque impossible d'établir le locrien comme centre tonal." },
  { q: "Quelle est la différence entre 'Dm en ré mineur tonal' et 'Dm en D dorien' ?", opts: ["Aucune — c'est le même accord", "En ré mineur, IV est Gm ; en D dorien, IV est G majeur — la couleur harmonique est totalement différente", "En dorien, Im est majeur", "En ré mineur, la tonique est Do"], a: 1, fb: "Dm existe dans les deux, mais l'environnement harmonique diffère. En D mineur naturel : IV = Gm (avec Bb). En D dorien : IV = G majeur (avec B naturel). Ce seul accord change complètement la couleur du mode." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q: "In modal harmonization, what is the main goal of the chords?", opts: ["Create tension and resolution (SD→D→T)", "Maintain and color the mode without mandatory resolution", "Always end on V7→I", "Use all 7 diatonic chords equally"], a: 1, fb: "In modal music, chords must preserve the color of the mode — not create tonal tension. Oscillating between Im and a characteristic chord is enough; a V7→I resolution would destroy the modal identity." },
{ q: "Why should V7→I be avoided in a modal context?", opts: ["V7 is too dissonant", "V7 introduces the leading tone absent from the mode, creating a tonal resolution that erases the modal color", "V7 does not exist in modal music", "V7 is reserved for major modes"], a: 1, fb: "The leading tone in V7 creates an irresistible pull toward I — that is the tonal engine. In modal music, we want to avoid this attraction in order to maintain the floating color of the mode." },
{ q: "What is the fundamental difference between tonal and modal harmonization?", opts: ["Tonal uses more chords", "Tonal organizes chords in a tension/resolution hierarchy; modal maintains a stable color", "Modal uses only minor chords", "Tonal is more modern"], a: 1, fb: "Tonal = functional hierarchy (T, SD, D) with mandatory resolution. Modal = stable harmonic color — chords oscillate around the tonic without pulling toward it imperatively." },
{ q: "How do you identify the characteristic chord of a mode for harmonization?", opts: ["It is always chord IV", "It is the chord built on the distinctive note of the mode compared to the standard major or minor scale", "It is always chord ♭VII", "It is the first diatonic chord"], a: 1, fb: "The characteristic chord highlights the distinctive note of the mode. In Dorian: IV major (major 6th). In Phrygian: ♭II (flatted 2nd). In Lydian: II major (#4). In Mixolydian: ♭VII (minor 7th)." },
{ q: "Which of these progressions is modal (not tonal)?", opts: ["I – IV – V7 – I", "IIm – V7 – Imaj7", "Im – IV – Im – IV (Dorian)", "I – VI – II – V"], a: 2, fb: "Im – IV – Im – IV (D Dorian: Dm – G – Dm – G) is a modal progression — it oscillates without a V7→I resolution. The other three are classic tonal progressions with an active V7 moving to I." },
{ q: "What maintains the modal color in a harmonization?", opts: ["Always playing in minor", "Regularly using the characteristic chord of the mode and avoiding V7→I", "Avoiding all dissonance", "Staying on a single chord"], a: 1, fb: "Modal color is maintained by two elements: using the characteristic chord (which contains the distinctive note) and avoiding V7→I (which would create a tonal resolution)." },
{ q: "How does modal music sound compared to tonal music?", opts: ["Modal music 'arrives somewhere' like tonal music", "Modal music 'stays somewhere' — it floats and colors rather than progresses", "Modal music is always faster", "Modal music uses more dissonances"], a: 1, fb: "Tonal music creates a sense of direction and arrival (tension → resolution). Modal music creates a sense of suspension, of stable color — it 'is' somewhere rather than 'arriving' there." },
{ q: "In modal music, what does the characteristic chord of the mode functionally replace?", opts: ["The subdominant chord", "The dominant V7 — it brings harmonic interest without creating tonal resolution", "The tonic", "The Neapolitan sixth chord"], a: 1, fb: "The characteristic chord (IV in Dorian, ♭II in Phrygian…) is the harmonic point of interest in the mode — it avoids the monotony of a single chord, but without the directional pull of V7." },
{ q: "What progression characterizes harmonization in the Dorian mode?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 1, fb: "Im – IV in Dorian (e.g. Dm – G in D Dorian) is the fundamental modal progression. IV is major thanks to the major 6th — this is the jazz-modal color of Miles Davis's So What." },
{ q: "In D Dorian, what chord is IV and why is it characteristic?", opts: ["Gm — it recalls natural minor", "G major — the major 6th (B natural) makes it major", "G7 — it creates tension", "Gdim — it is unstable"], a: 1, fb: "In D Dorian: D E F G A B C. On G: G B D = G major. The B natural (major 6th) makes this chord major. In D natural minor, IV would be Gm — this difference is what creates the Dorian color." },
{ q: "Which chord should be avoided in Dorian harmonization?", opts: ["IV major (G in D Dorian)", "V7 (A7 in D Dorian)", "♭III (F in D Dorian)", "♭VII (C in D Dorian)"], a: 1, fb: "A7 (V7 in D Dorian) introduces C# — the leading tone that Dorian does not have (C natural). This C# creates a tonal pull toward Dm that breaks the modal color and transforms Dorian into harmonic minor." },
{ q: "Which Miles Davis piece is the quintessential Dorian modal example?", opts: ["Kind of Blue — All Blues", "So What (D Dorian)", "Round Midnight", "Autumn Leaves"], a: 1, fb: "So What (1959) is entirely in D Dorian. Miles Davis and Bill Evans build the harmony on Dm7–G (Im–IV), never calling for a tonal resolution — it is the archetype of modal jazz." },
{ q: "In Dorian harmonization, Im – IV creates:", opts: ["A tension that demands resolution", "A colorful oscillation without resolution", "A perfect cadence", "A subdominant-to-dominant movement"], a: 1, fb: "Im – IV in Dorian (Dm – G) oscillates between two chords without functional hierarchy. No tension calls for resolution — it is a color that sustains itself, floats, breathes." },
{ q: "In G Dorian, what chord is IV?", opts: ["Cm (C minor)", "C major", "Cdim", "C7"], a: 1, fb: "G Dorian: G A Bb C D E F. On C: C E G = C major. The major 6th of Dorian (E natural instead of Eb) makes chord IV major — the harmonic hallmark of the Dorian mode." },
{ q: "Bossa Nova often uses Dorian because:", opts: ["Dorian is exclusively Brazilian", "The major 6th of Dorian creates a sophisticated color — half dark, half bright — perfect for saudade", "Dorian is the simplest of modes", "Bossa Nova avoids major chords"], a: 1, fb: "Brazilian saudade — sweet and luminous melancholy — finds its perfect harmonic expression in Dorian. The major 6th prevents IV from sounding dark (Gm) — it stays bright (G), creating the balance between shadow and light." },
{ q: "What is the characteristic cadence of the Phrygian mode?", opts: ["V7 – I", "IV – I", "♭II – Im (Phrygian cadence)", "♭VII – I"], a: 2, fb: "The Phrygian cadence ♭II→Im (e.g. F→Em in E Phrygian) is the harmonic DNA of flamenco. The descending half-step motion creates a unique tension different from V7→I." },
{ q: "In E Phrygian, what chord is ♭II?", opts: ["D major", "F major", "Eb major", "B major"], a: 1, fb: "E Phrygian: E F G A B C D. ♭II is built on F: F A C = F major. The flatted 2nd of Phrygian (F instead of F#) creates this very characteristic chord." },
{ q: "Why is the motion F→Em (in E Phrygian) so expressive?", opts: ["F is a fourth away from Em", "It is a descending half-step motion — the smallest of all intervals", "F is the dominant of Em", "It is a tritone"], a: 1, fb: "F→E is a descending half-step — the smallest and most tense interval. This ♭II→Im motion creates a powerful pull through chromatic proximity, very different from the tonal V7→I resolution." },
{ q: "Which musical genre primarily uses the Phrygian cadence?", opts: ["American blues", "Modal jazz", "Spanish flamenco", "Gospel"], a: 2, fb: "Spanish flamenco is built on the Phrygian cadence ♭II→Im and its variations. The dark, Mediterranean color of Phrygian — with its flatted 2nd — is the sonic identity of Andalusian music." },
{ q: "In Phrygian harmonization, which chord should be avoided?", opts: ["♭II (F in E Phrygian)", "Im (Em)", "V7 (B7 in E Phrygian)", "♭VII (D in E Phrygian)"], a: 2, fb: "B7 (V7 in E Phrygian) introduces D# — a leading tone foreign to Phrygian (D natural). This D# creates a tonal resolution toward Em, erasing the Phrygian color." },
{ q: "In A Phrygian, what chord is ♭II?", opts: ["G major", "Bb major", "B major", "Ab major"], a: 1, fb: "A Phrygian: A Bb C D E F G. ♭II is built on Bb: Bb D F = Bb major. The flatted 2nd (Bb instead of B) creates this characteristic chord of Phrygian." },
{ q: "The 'dark and Mediterranean' color is associated with which mode?", opts: ["Dorian", "Lydian", "Phrygian", "Aeolian"], a: 2, fb: "Phrygian is the mode of the Mediterranean — its flatted 2nd and the ♭II→Im cadence create a dark, intense, dramatic color. It is the sonic identity of flamenco and Spanish music." },
{ q: "What progression characterizes harmonization in the Lydian mode?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – II – I", "I – ♭VII – IV – I"], a: 2, fb: "I – II in Lydian (e.g. F – G in F Lydian) is the characteristic progression. II is major thanks to the #4 — a major–major ascending second motion impossible in a standard major scale (where II is minor)." },
{ q: "Why is chord II major in the Lydian mode?", opts: ["Because Lydian is a minor mode", "Because the #4 (augmented 4th) of Lydian is in chord II", "Because II is always major in modal music", "Because Lydian derives from the 4th degree"], a: 1, fb: "In F Lydian: F G A B C D E. On G (II): G B D = G major. The B natural (#4 of Lydian) is the third of G — it makes chord II major. In standard F major, II would be Gm (with Bb)." },
{ q: "Which film music composer makes abundant use of Lydian to evoke wonder?", opts: ["Ennio Morricone", "John Williams", "Hans Zimmer", "Bernard Herrmann"], a: 1, fb: "John Williams uses Lydian in E.T., Superman, and his magical scores. The #4 creates a bright and dreamlike color — the augmented 4th avoids the perfect stability of the major scale and makes the music 'float'." },
{ q: "In F Lydian, which chord should be avoided to preserve the color?", opts: ["G major (II)", "Bb (IV of standard F major)", "Am (IIIm)", "C (V)"], a: 1, fb: "Bb reintroduces exactly the note that Lydian replaces with B natural (#4). Playing Bb instantly erases the Lydian color and makes the scale sound like a standard major scale." },
{ q: "In C Lydian, what chord is II?", opts: ["Dm", "D major", "Ddim", "D7"], a: 1, fb: "C Lydian: C D E F# G A B. On D: D F# A = D major. The F# (#4 of Lydian) is the third of D — it makes chord II major and reveals the mode to the ear." },
{ q: "The 'bright and dreamlike' color is associated with which mode?", opts: ["Aeolian", "Phrygian", "Mixolydian", "Lydian"], a: 3, fb: "Lydian with its #4 creates a bright and dreamlike color. The augmented 4th avoids the perfect stability of the major scale — it floats, it shimmers. It is the mode of wonder and magic." },
{ q: "The main theme of The Simpsons begins with a:", opts: ["Phrygian leap (♭2)", "Ascending Lydian tritone (root to #4)", "Dominant chord", "Aeolian motion (♭VII)"], a: 1, fb: "The Simpsons theme begins with an ascending leap to the Lydian #4 — the tritone F→B in F Lydian. It is this slightly quirky #4 that creates such a recognizable color." },
{ q: "What progression is typical of the Mixolydian mode?", opts: ["Im – IV – Im", "Im – ♭VI – ♭VII – Im", "I – ♭VII – IV – I", "I – II – I"], a: 2, fb: "I – ♭VII – IV – I (e.g. G – F – C – G in G Mixolydian) is the quintessential rock/blues progression. The ♭VII (F) creates a return motion without a leading-tone resolution." },
{ q: "In G Mixolydian, what chord is ♭VII?", opts: ["F# major", "F minor", "F major", "Fdim"], a: 2, fb: "G Mixolydian: G A B C D E F. ♭VII is built on F: F A C = F major. The minor 7th (F instead of F#) makes this chord major — it is the harmonic hallmark of Mixolydian." },
{ q: "Why is V7 avoided in Mixolydian harmonization?", opts: ["V7 is too simple", "V7 introduces the leading tone (F# in G Mixolydian) absent from the mode, creating a resolution toward G", "V7 creates parallel fifths", "V7 changes the mode to Lydian"], a: 1, fb: "In G Mixolydian, F is ♭7 (the characteristic note). D7 (V7) introduces F# — the leading tone that does not exist in the mode. This F# creates a pull toward G (tonal resolution) that breaks the cyclical color of Mixolydian." },
{ q: "Which musical style is harmonically based on the Mixolydian mode?", opts: ["Baroque music", "Spanish flamenco", "Blues and rock", "Romantic music"], a: 2, fb: "Blues and rock primarily use Mixolydian. The I7 chord of the blues (with a minor 7th) is the Mixolydian chord. The I7–IV7–V7 blues progression is fundamentally Mixolydian." },
{ q: "Norwegian Wood by the Beatles is in which mode?", opts: ["Dorian", "Phrygian", "Aeolian", "Mixolydian"], a: 3, fb: "Norwegian Wood (1965) is in E Mixolydian. The minor 7th (D natural instead of D#) in the melody and harmony gives it that characteristic modal color — major but unresolved." },
{ q: "In D Mixolydian, what chord is ♭VII?", opts: ["C# major", "C minor", "C major", "Cdim"], a: 2, fb: "D Mixolydian: D E F# G A B C. On C: C E G = C major. The minor 7th (C instead of C#) is the characteristic note of Mixolydian — and this ♭VII major chord is its harmonic signature." },
{ q: "The 'energetic and cyclical without resolution' color is associated with which mode?", opts: ["Ionian", "Dorian", "Aeolian", "Mixolydian"], a: 3, fb: "Mixolydian creates perpetual energy — the progression I–♭VII–IV–I cycles without ever truly 'arriving'. The minor 7th prevents resolution to I while keeping the major color. This is the essence of blues and rock." },
{ q: "What progression is typical of the Aeolian mode?", opts: ["Im – IV – Im", "Im – ♭II – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 3, fb: "Im – ♭VI – ♭VII – Im (e.g. Am – F – G – Am in A Aeolian) is the most widespread natural minor progression in pop and rock. It oscillates without a leading tone, creating a gentle, natural melancholy." },
{ q: "In A Aeolian, why is ♭VII G major?", opts: ["Because G is the fifth of C", "Because in A Aeolian (A B C D E F G), the chord on G is G B D = G major", "Because G is always major in minor", "Because G is the relative tonic"], a: 1, fb: "A Aeolian: A B C D E F G. On G (♭VII): G B D = G major. The B natural in G gives a bright major chord on ♭VII — it is what keeps the color from being too dark." },
{ q: "How does Aeolian differ harmonically from harmonic minor?", opts: ["Aeolian has a major third", "Aeolian has no leading tone — its V is Vm (minor), not V7", "Aeolian has no 4th degree", "Aeolian uses the Neapolitan chord"], a: 1, fb: "In Aeolian, V = Em (minor, no leading tone). In harmonic minor, V = E7 (with G# leading tone). This leading tone creates tonal resolution. Aeolian avoids this tension — more natural, less directed." },
{ q: "The progression Am – F – G – Am is typically:", opts: ["Tonal (harmonic minor)", "Modal (natural Aeolian)", "Tonal (major)", "Pentatonic"], a: 1, fb: "Am – F – G – Am is purely Aeolian — with no E7 (V7). G (♭VII) and F (♭VI) are characteristic of natural/Aeolian minor. This is the progression of House of the Rising Sun, Losing My Religion…" },
{ q: "In A Aeolian, what problem does E7 (V7) cause?", opts: ["It is too low", "It introduces G# — the leading tone absent from Aeolian — creating a tonal resolution toward Am", "It creates parallel fifths", "It forces a shift to Lydian"], a: 1, fb: "E7 contains G# — the leading tone that Aeolian does not have (G natural). This G# imperatively calls for resolution to A, transforming the mode into harmonic minor and breaking the natural melancholy of Aeolian." },
{ q: "In E Aeolian, what chord is ♭VII?", opts: ["D# major", "D minor", "D major", "Ddim"], a: 2, fb: "E Aeolian: E F# G A B C D. On D: D F# A = D major. The D natural (♭7) makes chord ♭VII major — its presence harmonically characterizes the Aeolian mode and distinguishes its color from harmonic minor." },
{ q: "Stairway to Heaven by Led Zeppelin primarily uses:", opts: ["The Lydian mode", "The Mixolydian mode", "The Aeolian mode (natural minor)", "The Phrygian mode"], a: 2, fb: "Stairway to Heaven is built on A natural minor (A Aeolian) — the characteristic progression Am – G – F. The introspective melancholy of natural minor without a leading tone is typically Aeolian." },
{ q: "A major IV chord in a minor context most likely indicates which mode?", opts: ["Harmonic minor", "Dorian mode", "Phrygian mode", "Locrian mode"], a: 1, fb: "A major IV chord in a minor context is the harmonic signature of Dorian. In natural minor (Aeolian), IV would be minor. The presence of a major IV (e.g. G in D minor) signals the Dorian major 6th." },
{ q: "A ♭II chord in a minor context most likely indicates which mode?", opts: ["Dorian mode", "Harmonic minor", "Phrygian mode", "Aeolian mode"], a: 2, fb: "♭II in a minor context is the signature of Phrygian. The chord built on the flatted 2nd (e.g. F in E Phrygian) is unique to this mode — no other minor mode naturally possesses it." },
{ q: "A major ♭VII chord in a major context most likely indicates which mode?", opts: ["Lydian mode", "Ionian mode", "Mixolydian mode", "Dorian mode"], a: 2, fb: "A major ♭VII chord in a major context is the signature of Mixolydian. In a standard major scale, ♭VII does not exist (the 7th degree is diminished). The presence of a major ♭VII (e.g. F in G major) signals the Mixolydian minor 7th." },
{ q: "What is the difference between Im–IV (Dorian) and Im–Vm (Aeolian)?", opts: ["Im–IV is dynamically stronger", "Im–IV uses a major IV (Dorian, major 6th); Im–Vm uses a minor V (Aeolian, minor 6th)", "Im–Vm is a perfect cadence", "There is no difference"], a: 1, fb: "The difference lies in the 6th of the mode. Dorian: major 6th → IV is major (G in D Dorian). Aeolian: minor 6th → Vm is minor (Em in A Aeolian). These two chords create a radically different color." },
{ q: "Which progression is the most tonal among these options?", opts: ["Dm – G – Dm (Im–IV Dorian)", "Em – F – Em (♭II Phrygian)", "Am – Dm – E7 – Am", "G – F – C – G (Mixolydian)"], a: 2, fb: "Am – Dm – E7 – Am contains E7 (V7), which introduces G# (leading tone) and resolves tonally to Am — this is harmonic minor, not modal. The other three avoid V7→I and maintain a modal color." },
{ q: "To harmonize a rock melody with a riff G – F – C – G, the mode is:", opts: ["Ionian (G major)", "Dorian", "Mixolydian (G Mixolydian)", "Lydian"], a: 2, fb: "G – F – C – G = I – ♭VII – IV – I in G Mixolydian. F (♭VII) does not exist in standard G major (F# is natural there). The presence of F natural confirms G Mixolydian — the mode of blues and rock." },
{ q: "To harmonize a flamenco melody, which mode should you choose?", opts: ["Dorian (Im–IV)", "Phrygian (Im–♭II)", "Mixolydian (I–♭VII)", "Aeolian (Im–♭VI–♭VII)"], a: 1, fb: "Flamenco uses the Phrygian mode. The ♭II→Im cadence (e.g. F→Em in E Phrygian) is the harmonic DNA of flamenco — the dark, Mediterranean color comes directly from the flatted 2nd." },
{ q: "So What by Miles Davis (1959) is harmonized with:", opts: ["Phrygian chords", "Dorian chords (Dm7–G)", "Mixolydian chords", "Lydian chords"], a: 1, fb: "So What is in D Dorian. Miles Davis uses the oscillation Dm7 – G (Im – IV in Dorian) — no V7→I. The jazz-modal color comes from this major IV (G) in a minor context (Dm)." },
{ q: "A typical modal harmonization:", opts: ["Always contains V7→I", "Avoids V7→I and repeatedly uses the characteristic chord of the mode", "Uses only minor chords", "Modulates to the relative major"], a: 1, fb: "A modal harmonization rests on: avoiding V7→I (tonal resolution) and regularly using the characteristic chord (IV in Dorian, ♭II in Phrygian, etc.) that reveals the color of the mode." },
{ q: "What is the characteristic chord of the Aeolian mode?", opts: ["IV major", "♭II major", "♭VII major (no leading tone)", "II major"], a: 2, fb: "♭VII major harmonically distinguishes Aeolian from harmonic minor. In A Aeolian: G major (♭VII). The absence of a leading tone (G instead of G#) is the hallmark of natural Aeolian." },
{ q: "Which chord is unique to the Lydian mode among the major modes?", opts: ["IV major", "V dominant", "II major", "♭VII major"], a: 2, fb: "II major only exists in Lydian among the modes of the major scale. In Ionian and Mixolydian, II is minor. In Lydian, the #4 makes II major — it is the chord that 'gives away' the mode to the ear." },
{ q: "In the Phrygian mode, which chord does NOT belong to the mode?", opts: ["Im (Em in E Phrygian)", "♭II (F in E Phrygian)", "V7 (B7 in E Phrygian)", "♭VII (D in E Phrygian)"], a: 2, fb: "B7 contains D# — the leading tone absent from Phrygian (D natural). This chord is 'foreign' to the mode: it breaks the Phrygian color by creating a tonal pull toward Em." },
{ q: "Comparing Dorian and Aeolian: what is the single different note?", opts: ["The 3rd (major vs. minor)", "The 6th (major in Dorian, minor in Aeolian)", "The 5th (perfect vs. diminished)", "The 2nd (major vs. flatted)"], a: 1, fb: "Dorian and Aeolian share all the same scale degrees except the 6th: Dorian has a major 6th (B in D Dorian), Aeolian has a minor 6th (Bb in D Aeolian). This single note changes chord IV from Gm to G major — the entire color follows from it." },
{ q: "Comparing Mixolydian and Ionian: what is the single different note?", opts: ["The 3rd (major vs. minor)", "The 4th (perfect vs. augmented)", "The 7th (major in Ionian, minor in Mixolydian)", "The 5th (perfect vs. diminished)"], a: 2, fb: "Mixolydian = Ionian with ♭7. In G major: F# becomes F natural. This single alteration transforms chord VII from F#dim to F major (♭VII) — and creates the blues/rock color without resolution." },
{ q: "Why does modal music sometimes seem to 'float' or 'go in circles'?", opts: ["Because the musicians play the transitions poorly", "Because there is no mandatory tonal resolution — the chords oscillate rather than progress", "Because the tempo is too slow", "Because modes have no tonic"], a: 1, fb: "Tonal music creates direction and arrival (tension → resolution). Modal music creates suspension, stable color — chords oscillate around the tonic without pulling toward it imperatively. This is intentional." },
{ q: "Are Debussy's parallel chord progressions tonal or modal?", opts: ["Tonal — classical technique", "Modal — the chords color the mode without a functional role", "Atonal — no tonality", "Pentatonic"], a: 1, fb: "Debussy's parallel chords are a modal technique: the chords do not create functional tension (SD→D→T), they move like blocks of color — a liberation from the constraints of tonal counterpoint." },
{ q: "In which of Debussy's works is the modal influence most evident?", opts: ["Clair de Lune (classical minor)", "La Cathédrale engloutie (medieval modes and parallel chords)", "Chopin's Nocturnes (Romantic)", "Franck's Symphony"], a: 1, fb: "La Cathédrale engloutie (1910) uses medieval modes (Lydian, Mixolydian) and parallel chords to evoke a cathedral under the waves — the perfect example of Impressionist modal harmony." },
{ q: "What harmonic element allows you to identify a mode by ear?", opts: ["The speed of the progression", "The characteristic chord — the chord that contains the distinctive note of the mode", "The number of chords used", "The register of the melody"], a: 1, fb: "The characteristic chord 'reveals' the mode. Dorian: IV major. Phrygian: ♭II. Lydian: II major. Mixolydian: ♭VII. Aeolian: ♭VII without leading tone. It is the chord we hear as 'the color' of the mode." },
{ q: "The 12-bar blues I7 – IV7 – V7 progression is:", opts: ["Tonal (harmonic minor)", "Modal (Mixolydian)", "Atonal", "Modal (Dorian)"], a: 1, fb: "The blues is fundamentally Mixolydian: each chord (I, IV, V) has a minor 7th, and none resolves to another in a tonal way. It is a circular system that keeps turning, not a progression toward a final resolution." },
{ q: "In modal music, a 'pedal' is:", opts: ["A very low chord", "A note sustained in the bass beneath which the melody changes color", "A diminished chord", "A dominant chord"], a: 1, fb: "A pedal (sustained note or chord) maintains a fixed color while the melody explores the mode. It is a classic modal technique — the chord does not change functionally; it establishes a stable coloristic center." },
{ q: "Oye Como Va by Santana is in which mode?", opts: ["Phrygian", "Lydian", "Dorian", "Aeolian"], a: 2, fb: "Oye Como Va is in A Dorian. The progression Am–D (Im–IV) is typically Dorian — chord IV (D major) reveals the major 6th (F#) of the mode. Carlos Santana is one of the masters of the Dorian sound." },
{ q: "What is the harmonic signature of Dorian compared to Phrygian?", opts: ["Dorian has ♭II; Phrygian has IV major", "Dorian has IV major; Phrygian has ♭II", "Both have the same characteristic chord", "Dorian has ♭VII; Phrygian has #IV"], a: 1, fb: "Dorian: the characteristic chord is IV major (thanks to the major 6th). Phrygian: the characteristic chord is ♭II (thanks to the flatted 2nd). These two chords immediately 'give away' the mode to the ear." },
{ q: "In the harmonization Am – G – F – E7, where is the 'departure' from Aeolian mode?", opts: ["In Am (tonic)", "In E7 — G# is not in Aeolian mode (which has G♮)", "In F (subdominant)", "In G (subtonic)"], a: 1, fb: "E7 contains G# — not part of the A Aeolian mode (which has G♮). E7 is borrowed from the harmonic minor scale. This alteration creates a leading tone to A, adding tonality to the otherwise modal progression." },
];

const questionsEs: Question[] = [{ q: "En armonización modal, ¿cuál es el objetivo principal de los acordes?", opts: ["Crear tensión y resolución (SD→D→T)", "Mantener y colorear el modo sin resolución obligatoria", "Terminar siempre en V7→I", "Usar los 7 acordes diatónicos de manera equitativa"], a: 1, fb: "En modal, los acordes deben preservar el color del modo — no crear tensión tonal. La oscilación entre Im y un acorde característico es suficiente; una resolución V7→I destruiría la identidad modal." },
{ q: "¿Por qué hay que evitar V7→I en un contexto modal?", opts: ["V7 es demasiado disonante", "V7 introduce la sensible ausente del modo, creando una resolución tonal que borra el color modal", "V7 no existe en música modal", "V7 está reservado para los modos mayores"], a: 1, fb: "La sensible en V7 crea una tensión irresistible hacia I — es el motor tonal. En modal, se quiere evitar esa atracción para mantener el color flotante del modo." },
{ q: "¿Cuál es la diferencia fundamental entre una armonización tonal y modal?", opts: ["La tonal usa más acordes", "La tonal organiza los acordes en jerarquía tensión/resolución; la modal mantiene un color estable", "La modal solo usa acordes menores", "La tonal es más moderna"], a: 1, fb: "Tonal = jerarquía funcional (T, SD, D) con resolución obligatoria. Modal = color armónico estable — los acordes oscilan alrededor de la tónica sin llamarla de manera imperativa." },
{ q: "¿Cómo identificar el acorde característico de un modo para la armonización?", opts: ["Siempre es el acorde IV", "Es el acorde construido sobre la nota distintiva del modo respecto a la escala mayor o menor estándar", "Siempre es el acorde ♭VII", "Es el primer acorde diatónico"], a: 1, fb: "El acorde característico pone en valor la nota distintiva del modo. En dórico: IV mayor (6ª mayor). En frigio: ♭II (2ª bemolizada). En lidio: II mayor (#4). En mixolidio: ♭VII (7ª menor)." },
{ q: "¿Cuál de estas progresiones es modal (no tonal)?", opts: ["I – IV – V7 – I", "IIm – V7 – Imaj7", "Im – IV – Im – IV (dórico)", "I – VI – II – V"], a: 2, fb: "Im – IV – Im – IV (D dórico: Dm – G – Dm – G) es una progresión modal — oscila sin resolución V7→I. Las otras 3 son progresiones tonales clásicas con un V7 activo hacia I." },
{ q: "¿Qué mantiene el color modal en una armonización?", opts: ["Tocar siempre en menor", "Usar regularmente el acorde característico del modo y evitar V7→I", "Evitar toda disonancia", "Quedarse en un solo acorde"], a: 1, fb: "El color modal se mantiene mediante dos elementos: el uso del acorde característico (que contiene la nota distintiva) y la evitación de V7→I (que crearía una resolución tonal)." },
{ q: "¿Cómo suena la música modal comparada con la música tonal?", opts: ["La modal 'llega a algún lugar' como la tonal", "La modal 'permanece en algún lugar' — flota y colorea en lugar de progresar", "La modal es siempre más rápida", "La modal usa más disonancias"], a: 1, fb: "La música tonal crea un sentimiento de dirección y llegada (tensión → resolución). La música modal crea un sentimiento de suspensión, de color estable — 'está' en algún lugar en lugar de 'llegar' a él." },
{ q: "En modal, ¿qué reemplaza funcionalmente el acorde característico del modo?", opts: ["El acorde de subdominante", "La dominante V7 — aporta interés armónico sin crear resolución tonal", "La tónica", "El acorde de sexta napolitana"], a: 1, fb: "El acorde característico (IV en dórico, ♭II en frigio…) es el punto de interés armónico del modo — evita la monotonía de un único acorde, pero sin la atracción direccional de V7." },
{ q: "¿Qué progresión caracteriza la armonización en modo dórico?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 1, fb: "Im – IV en dórico (ej. Dm – G en D dórico) es la progresión modal fundamental. IV es mayor gracias a la 6ª mayor — es el color jazz-modal de So What de Miles Davis." },
{ q: "En D dórico, ¿qué acorde es IV y por qué es característico?", opts: ["Gm — recuerda al menor natural", "G mayor — la 6ª mayor (B natural) lo hace mayor", "G7 — crea tensión", "Gdim — es inestable"], a: 1, fb: "En D dórico: D E F G A B C. Sobre G: G B D = G mayor. El B natural (6ª mayor) hace que este acorde sea mayor. En D menor natural, IV sería Gm — esa diferencia crea el color dórico." },
{ q: "¿Qué acorde hay que evitar en la armonización dórica?", opts: ["IV mayor (G en D dórico)", "V7 (A7 en D dórico)", "♭III (F en D dórico)", "♭VII (C en D dórico)"], a: 1, fb: "A7 (V7 en D dórico) introduce C# — la sensible que el dórico no tiene (C natural). Este C# crea una atracción tonal hacia Dm que destruye el color modal y transforma el dórico en menor armónico." },
{ q: "¿Qué obra de Miles Davis es el ejemplo modal dórico por excelencia?", opts: ["Kind of Blue — All Blues", "So What (D dórico)", "Round Midnight", "Autumn Leaves"], a: 1, fb: "So What (1959) está íntegramente en D dórico. Miles Davis y Bill Evans construyen la armonía sobre Dm7–G (Im–IV), sin llamar nunca a una resolución tonal — es el arquetipo del jazz modal." },
{ q: "En armonización dórica, Im – IV crea:", opts: ["Una tensión que pide resolución", "Una oscilación coloreada sin resolución", "Una cadencia perfecta", "Un movimiento de subdominante hacia dominante"], a: 1, fb: "Im – IV en dórico (Dm – G) oscila entre dos acordes sin jerarquía funcional. Sin tensión que llame a la resolución — es un color que se mantiene, flota, respira." },
{ q: "En G dórico, ¿qué acorde es IV?", opts: ["Cm (C menor)", "C mayor", "Cdim", "C7"], a: 1, fb: "G dórico: G A Bb C D E F. Sobre C: C E G = C mayor. La 6ª mayor del dórico (E natural en lugar de Eb) hace que este acorde IV sea mayor — la marca armónica del modo dórico." },
{ q: "La Bossa Nova utiliza a menudo el dórico porque:", opts: ["El dórico es únicamente brasileño", "La 6ª mayor del dórico crea un color sofisticado a medio camino entre lo oscuro y lo luminoso, perfecto para la saudade", "El dórico es el más simple de los modos", "La Bossa Nova evita los acordes mayores"], a: 1, fb: "La saudade brasileña — melancolía dulce y luminosa — encuentra en el dórico su expresión armónica perfecta. La 6ª mayor impide que IV sea oscuro (Gm) — permanece luminoso (G), creando el equilibrio entre sombra y luz." },
{ q: "¿Cuál es la cadencia característica del modo frigio?", opts: ["V7 – I", "IV – I", "♭II – Im (cadencia frigia)", "♭VII – I"], a: 2, fb: "La cadencia frigia ♭II→Im (ej. F→Em en E frigio) es el ADN armónico del flamenco. El movimiento descendente por semitono crea una tensión única diferente de V7→I." },
{ q: "En E frigio, ¿qué acorde es ♭II?", opts: ["D mayor", "F mayor", "Eb mayor", "B mayor"], a: 1, fb: "E frigio: E F G A B C D. El ♭II se construye sobre F: F A C = F mayor. La 2ª bemolizada del frigio (F en lugar de F#) crea este acorde muy característico." },
{ q: "¿Por qué el movimiento F→Em (en E frigio) es tan expresivo?", opts: ["F es una cuarta de Em", "Es un movimiento descendente por semitono — el más estrecho de todos los intervalos", "F es la dominante de Em", "Es un tritono"], a: 1, fb: "F→E es un semitono descendente — el intervalo más pequeño y más tenso. Este movimiento ♭II→Im crea una atracción poderosa por proximidad cromática, muy diferente de la resolución tonal V7→I." },
{ q: "¿Qué género musical utiliza principalmente la cadencia frigia?", opts: ["Blues americano", "Jazz modal", "Flamenco español", "Gospel"], a: 2, fb: "El flamenco español se funda en la cadencia frigia ♭II→Im y sus variaciones. El color oscuro y mediterráneo del frigio — con su 2ª bemolizada — es la identidad sonora de la música andaluza." },
{ q: "En armonización frigia, ¿qué acorde hay que evitar?", opts: ["♭II (F en E frigio)", "Im (Em)", "V7 (B7 en E frigio)", "♭VII (D en E frigio)"], a: 2, fb: "B7 (V7 en E frigio) introduce D# — una sensible ajena al frigio (D natural). Este D# crea una resolución tonal hacia Em, borrando el color frigio." },
{ q: "En A frigio, ¿qué acorde es ♭II?", opts: ["G mayor", "Bb mayor", "B mayor", "Ab mayor"], a: 1, fb: "A frigio: A Bb C D E F G. El ♭II se construye sobre Bb: Bb D F = Bb mayor. La 2ª bemolizada (Bb en lugar de B) crea este acorde característico del frigio." },
{ q: "El color 'oscuro y mediterráneo' está asociado a qué modo?", opts: ["Dórico", "Lidio", "Frigio", "Eólico"], a: 2, fb: "El frigio es el modo del mediterráneo — su 2ª bemolizada y la cadencia ♭II→Im crean un color oscuro, intenso, dramático. Es la identidad sonora del flamenco y la música española." },
{ q: "¿Qué progresión caracteriza la armonización en modo lidio?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – II – I", "I – ♭VII – IV – I"], a: 2, fb: "I – II en lidio (ej. F – G en F lidio) es la progresión característica. El II es mayor gracias al #4 — un movimiento de segunda ascendente mayor–mayor imposible en escala mayor estándar (donde II es menor)." },
{ q: "¿Por qué el acorde II es mayor en el modo lidio?", opts: ["Porque el lidio es un modo menor", "Porque el #4 (4ª aumentada) del lidio está en el acorde II", "Porque II es siempre mayor en modal", "Porque el lidio proviene del IVº grado"], a: 1, fb: "En F lidio: F G A B C D E. Sobre G (II): G B D = G mayor. El B natural (#4 del lidio) es la tercera de G — hace que el acorde II sea mayor. En F mayor estándar, II sería Gm (con Bb)." },
{ q: "¿Qué compositor de música de cine utiliza abundantemente el lidio para evocar lo maravilloso?", opts: ["Ennio Morricone", "John Williams", "Hans Zimmer", "Bernard Herrmann"], a: 1, fb: "John Williams usa el lidio en E.T., Superman y sus músicas mágicas. El #4 crea un color luminoso y onírico — la 4ª aumentada evita la estabilidad perfecta de la escala mayor y hace 'flotar' la música." },
{ q: "En F lidio, ¿qué acorde hay que evitar para preservar el color?", opts: ["G mayor (II)", "Bb (IV de F mayor estándar)", "Am (IIIm)", "C (V)"], a: 1, fb: "Bb reintroduce exactamente la nota que el lidio reemplaza por B natural (#4). Tocar Bb borra instantáneamente el color lidio y hace escuchar una escala mayor estándar." },
{ q: "En C lidio, ¿qué acorde es II?", opts: ["Dm", "D mayor", "Ddim", "D7"], a: 1, fb: "C lidio: C D E F# G A B. Sobre D: D F# A = D mayor. El F# (#4 del lidio) es la tercera de D — hace que el acorde II sea mayor y revela el modo al oído." },
{ q: "El color 'luminoso y onírico' está asociado a qué modo?", opts: ["Eólico", "Frigio", "Mixolidio", "Lidio"], a: 3, fb: "El lidio con su #4 crea un color luminoso y onírico. La 4ª aumentada evita la estabilidad perfecta de la escala mayor — flota, brilla. Es el modo del asombro y la magia." },
{ q: "El tema principal de Los Simpson comienza con un:", opts: ["Salto frigio (♭2)", "Tritono ascendente lidio (fundamental hacia #4)", "Acorde de dominante", "Movimiento eólico (♭VII)"], a: 1, fb: "El tema de Los Simpson comienza con un salto ascendente hacia el #4 lidio — el tritono F→B en F lidio. Es ese #4 ligeramente extraño el que crea ese color tan reconocible." },
{ q: "¿Qué progresión es típica del modo mixolidio?", opts: ["Im – IV – Im", "Im – ♭VI – ♭VII – Im", "I – ♭VII – IV – I", "I – II – I"], a: 2, fb: "I – ♭VII – IV – I (ej. G – F – C – G en G mixolidio) es la progresión rock/blues por excelencia. El ♭VII (F) crea un movimiento de retorno sin resolución de sensible." },
{ q: "En G mixolidio, ¿qué acorde es ♭VII?", opts: ["F# mayor", "F menor", "F mayor", "Fdim"], a: 2, fb: "G mixolidio: G A B C D E F. El ♭VII se construye sobre F: F A C = F mayor. La 7ª menor (F en lugar de F#) hace que este acorde sea mayor — es la marca armónica del mixolidio." },
{ q: "¿Por qué se evita V7 en la armonización mixolidia?", opts: ["V7 es demasiado simple", "V7 introduce la sensible (F# en G mixolidio) ausente del modo, creando una resolución hacia G", "V7 crea una quinta paralela", "V7 cambia el modo a lidio"], a: 1, fb: "En G mixolidio, F es ♭7 (nota característica). D7 (V7) introduce F# — la sensible que no existe en el modo. Este F# crea una tensión hacia G (resolución tonal) que destruye el color cíclico del mixolidio." },
{ q: "¿Qué estilo musical está armónicamente basado en el modo mixolidio?", opts: ["Música barroca", "Flamenco español", "Blues y rock", "Música romántica"], a: 2, fb: "El blues y el rock usan principalmente el mixolidio. El acorde I7 del blues (con 7ª menor) es el acorde del mixolidio. La progresión I7–IV7–V7 del blues es fundamentalmente mixolidia." },
{ q: "Norwegian Wood de los Beatles está en qué modo?", opts: ["Dórico", "Frigio", "Eólico", "Mixolidio"], a: 3, fb: "Norwegian Wood (1965) está en E mixolidio. La 7ª menor (D natural en lugar de D#) en la melodía y la armonía da ese color modal característico — mayor pero sin resolver." },
{ q: "En D mixolidio, ¿qué acorde es ♭VII?", opts: ["C# mayor", "C menor", "C mayor", "Cdim"], a: 2, fb: "D mixolidio: D E F# G A B C. Sobre C: C E G = C mayor. La 7ª menor (C en lugar de C#) es la nota característica del mixolidio — y este acorde ♭VII mayor es su firma armónica." },
{ q: "El color 'enérgico y cíclico sin resolución' está asociado a qué modo?", opts: ["Jónico", "Dórico", "Eólico", "Mixolidio"], a: 3, fb: "El mixolidio crea una energía perpetua — la progresión I–♭VII–IV–I gira sin llegar nunca realmente a ningún sitio. La 7ª menor impide la resolución hacia I manteniendo el color mayor. Es la esencia del blues y del rock." },
{ q: "¿Qué progresión es típica del modo eólico?", opts: ["Im – IV – Im", "Im – ♭II – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 3, fb: "Im – ♭VI – ♭VII – Im (ej. Am – F – G – Am en A eólico) es la progresión menor natural más extendida en pop y rock. Oscila sin sensible, creando una melancolía dulce y natural." },
{ q: "En A eólico, ¿por qué ♭VII es G mayor?", opts: ["Porque G es la quinta de C", "Porque en A eólico (A B C D E F G), el acorde sobre G es G B D = G mayor", "Porque G es siempre mayor en menor", "Porque G es la tónica relativa"], a: 1, fb: "A eólico: A B C D E F G. Sobre G (♭VII): G B D = G mayor. El B natural en G da un acorde mayor luminoso sobre el ♭VII — es él quien impide que el color sea demasiado oscuro." },
{ q: "¿Cómo se distingue el eólico del menor armónico armónicamente?", opts: ["El eólico tiene una tercera mayor", "El eólico no tiene sensible — su V es Vm (menor), no V7", "El eólico no tiene IVº grado", "El eólico usa el acorde napolitano"], a: 1, fb: "En eólico, V = Em (menor, sin sensible). En menor armónico, V = E7 (con G# sensible). Esta sensible crea la resolución tonal. El eólico evita esa tensión — más natural, menos dirigido." },
{ q: "La progresión Am – F – G – Am es típicamente:", opts: ["Tonal (menor armónico)", "Modal (eólico natural)", "Tonal (mayor)", "Pentatónica"], a: 1, fb: "Am – F – G – Am es puramente eólica — sin E7 (V7). G (♭VII) y F (♭VI) son característicos del menor natural/eólico. Es la progresión de House of the Rising Sun, Losing My Religion..." },
{ q: "En A eólico, ¿qué problema plantea E7 (V7)?", opts: ["Es demasiado grave", "Introduce G# — la sensible ausente del eólico — creando una resolución tonal hacia Am", "Crea una quinta paralela", "Fuerza el paso al lidio"], a: 1, fb: "E7 contiene G# — la sensible que el eólico no tiene (G natural). Este G# llama imperativamente a la resolución hacia A, transformando el modo en menor armónico y rompiendo la melancolía natural del eólico." },
{ q: "En E eólico, ¿qué acorde es ♭VII?", opts: ["D# mayor", "D menor", "D mayor", "Ddim"], a: 2, fb: "E eólico: E F# G A B C D. Sobre D: D F# A = D mayor. El D natural (♭7) hace que el acorde ♭VII sea mayor — su presencia caracteriza armónicamente el modo eólico y distingue su color del menor armónico." },
{ q: "Stairway to Heaven de Led Zeppelin utiliza principalmente:", opts: ["El modo lidio", "El modo mixolidio", "El modo eólico (menor natural)", "El modo frigio"], a: 2, fb: "Stairway to Heaven se apoya en A menor natural (A eólico) — la progresión Am – G – F característica. La melancolía introspectiva del menor natural sin sensible es típicamente eólica." },
{ q: "Un acorde IV mayor en un contexto menor indica probablemente qué modo?", opts: ["Menor armónico", "Modo dórico", "Modo frigio", "Modo locrio"], a: 1, fb: "IV mayor en un contexto menor es la firma armónica del dórico. En menor natural (eólico), IV sería menor. La presencia de un IV mayor (ej. G en D menor) señala la 6ª mayor dórica." },
{ q: "Un acorde ♭II en un contexto menor indica probablemente qué modo?", opts: ["Modo dórico", "Menor armónico", "Modo frigio", "Modo eólico"], a: 2, fb: "♭II en un contexto menor es la firma del frigio. El acorde construido sobre la 2ª bemolizada (ej. F en E frigio) es único de este modo — ningún otro modo menor lo posee de manera natural." },
{ q: "Un acorde ♭VII mayor en un contexto mayor indica probablemente qué modo?", opts: ["Modo lidio", "Modo jónico", "Modo mixolidio", "Modo dórico"], a: 2, fb: "♭VII mayor en un contexto mayor es la firma del mixolidio. En escala mayor estándar, ♭VII no existe (el VIIº grado es disminuido). La presencia de ♭VII mayor (ej. F en G mayor) señala la 7ª menor mixolidia." },
{ q: "¿Cuál es la diferencia entre Im–IV (dórico) e Im–Vm (eólico)?", opts: ["Im–IV es más fuerte dinámicamente", "Im–IV usa IV mayor (dórico, 6ª mayor); Im–Vm usa V menor (eólico, 6ª menor)", "Im–Vm es una cadencia perfecta", "No hay diferencia"], a: 1, fb: "La diferencia es la 6ª del modo. Dórico: 6ª mayor → IV es mayor (G en D dórico). Eólico: 6ª menor → Vm es menor (Em en A eólico). Estos dos acordes crean un color radicalmente diferente." },
{ q: "¿Cuál de estas progresiones es la más tonal entre las opciones?", opts: ["Dm – G – Dm (Im–IV dórico)", "Em – F – Em (♭II frigio)", "Am – Dm – E7 – Am", "G – F – C – G (mixolidio)"], a: 2, fb: "Am – Dm – E7 – Am contiene E7 (V7) que introduce G# (sensible) y resuelve tonalmente hacia Am — es menor armónico, no modal. Las otras 3 evitan V7→I y mantienen un color modal." },
{ q: "Para armonizar una melodía rock con un riff G – F – C – G, el modo es:", opts: ["Jónico (G mayor)", "Dórico", "Mixolidio (G mixolidio)", "Lidio"], a: 2, fb: "G – F – C – G = I – ♭VII – IV – I en G mixolidio. El F (♭VII) no existe en G mayor estándar (F# es natural allí). La presencia de F natural confirma el G mixolidio — modo del blues y del rock." },
{ q: "Para armonizar una melodía de flamenco, ¿qué modo elegir?", opts: ["Dórico (Im–IV)", "Frigio (Im–♭II)", "Mixolidio (I–♭VII)", "Eólico (Im–♭VI–♭VII)"], a: 1, fb: "El flamenco usa el modo frigio. La cadencia ♭II→Im (ej. F→Em en E frigio) es el ADN armónico del flamenco — el color oscuro y mediterráneo viene directamente de la 2ª bemolizada." },
{ q: "So What de Miles Davis (1959) está armonizado con:", opts: ["Acordes frigios", "Acordes dóricos (Dm7–G)", "Acordes mixolidios", "Acordes lidios"], a: 1, fb: "So What está en D dórico. Miles Davis usa la oscilación Dm7 – G (Im – IV en dórico) — sin V7→I. El color jazz-modal viene de ese IV mayor (G) en un contexto menor (Dm)." },
{ q: "Una armonización modal típica:", opts: ["Contiene siempre V7→I", "Evita V7→I y usa el acorde característico del modo de manera repetida", "Solo usa acordes menores", "Modula hacia la relativa mayor"], a: 1, fb: "Una armonización modal se basa en: evitar V7→I (resolución tonal) y usar regularmente el acorde característico (IV en dórico, ♭II en frigio, etc.) que revela el color del modo." },
{ q: "¿Cuál es el acorde característico del modo eólico?", opts: ["IV mayor", "♭II mayor", "♭VII mayor (sin sensible)", "II mayor"], a: 2, fb: "♭VII mayor distingue armónicamente el eólico del menor armónico. En A eólico: G mayor (♭VII). La ausencia de sensible (G en lugar de G#) es la marca del eólico natural." },
{ q: "¿Qué acorde es único del modo lidio entre los modos mayores?", opts: ["IV mayor", "V dominante", "II mayor", "♭VII mayor"], a: 2, fb: "II mayor solo existe en lidio entre los modos de la escala mayor. En jónico y mixolidio, II es menor. En lidio, el #4 hace que II sea mayor — es el acorde que 'delata' el modo al oído." },
{ q: "En modo frigio, ¿qué acorde NO pertenece al modo?", opts: ["Im (Em en E frigio)", "♭II (F en E frigio)", "V7 (B7 en E frigio)", "♭VII (D en E frigio)"], a: 2, fb: "B7 contiene D# — la sensible ausente del frigio (D natural). Este acorde es 'ajeno' al modo: destruye el color frigio creando una atracción tonal hacia Em." },
{ q: "Comparar dórico y eólico: ¿cuál es la única nota diferente?", opts: ["La 3ª (mayor vs menor)", "La 6ª (mayor en dórico, menor en eólico)", "La 5ª (justa vs disminuida)", "La 2ª (mayor vs bemolizada)"], a: 1, fb: "Dórico y eólico tienen los mismos grados excepto la 6ª: dórico tiene 6ª mayor (B en D dórico), eólico tiene 6ª menor (Bb en D eólico). Esa sola nota cambia el acorde IV de Gm a G mayor — todo el color deriva de ahí." },
{ q: "Comparar mixolidio y jónico: ¿cuál es la única nota diferente?", opts: ["La 3ª (mayor vs menor)", "La 4ª (justa vs aumentada)", "La 7ª (mayor en jónico, menor en mixolidio)", "La 5ª (justa vs disminuida)"], a: 2, fb: "Mixolidio = jónico con ♭7. En G mayor: F# se convierte en F natural. Esa única alteración transforma el acorde VII de F#dim en F mayor (♭VII) — y crea el color blues/rock sin resolución." },
{ q: "¿Por qué la música modal parece a veces 'flotar' o 'girar en círculos'?", opts: ["Porque los músicos tocan mal las transiciones", "Porque no hay resolución tonal obligatoria — los acordes oscilan en lugar de progresar", "Porque el tempo es demasiado lento", "Porque los modos no tienen tónica"], a: 1, fb: "La música tonal crea dirección y llegada (tensión → resolución). La música modal crea suspensión, color estable — los acordes oscilan alrededor de la tónica sin llamarla de manera imperativa. Es algo buscado." },
{ q: "¿Las progresiones de acordes paralelos de Debussy son tonales o modales?", opts: ["Tonales — técnica clásica", "Modales — los acordes colorean el modo sin rol funcional", "Atonales — sin tonalidad", "Pentatónicas"], a: 1, fb: "Los acordes paralelos de Debussy son una técnica modal: los acordes no crean tensión funcional (SD→D→T), se desplazan como bloques de color — liberación de las restricciones del contrapunto tonal." },
{ q: "¿En qué obra de Debussy es más evidente la influencia modal?", opts: ["Clair de Lune (menor clásico)", "La Cathédrale engloutie (modos medievales y acordes paralelos)", "Nocturnos de Chopin (romántico)", "Sinfonía de Franck"], a: 1, fb: "La Cathédrale engloutie (1910) usa modos medievales (lidio, mixolidio) y acordes paralelos para evocar la catedral bajo el agua — el ejemplo perfecto de la armonía modal impresionista." },
];

const questionsDe: Question[] = [{ q: "Was ist das Hauptziel der Akkorde bei der modalen Harmonisierung?", opts: ["Spannung und Auflösung erzeugen (SD→D→T)", "Den Modus beibehalten und färben, ohne obligatorische Auflösung", "Immer auf V7→I enden", "Die 7 diatonischen Akkorde gleichmäßig verwenden"], a: 1, fb: "Im Modalen müssen die Akkorde die Farbe des Modus bewahren – nicht tonale Spannung erzeugen. Das Pendeln zwischen Im und einem charakteristischen Akkord genügt; eine V7→I-Auflösung würde die modale Identität zerstören." },
{ q: "Warum sollte V7→I in einem modalen Kontext vermieden werden?", opts: ["V7 ist zu dissonant", "V7 führt den Leitton ein, der dem Modus fehlt, und erzeugt eine tonale Auflösung, die die modale Farbe auslöscht", "V7 existiert in der Modalmusik nicht", "V7 ist den Dur-Modi vorbehalten"], a: 1, fb: "Der Leitton in V7 erzeugt eine unwiderstehliche Anziehung zu I – das ist der tonale Motor. Im Modalen will man diese Anziehung vermeiden, um die schwebende Farbe des Modus beizubehalten." },
{ q: "Was ist der grundlegende Unterschied zwischen tonaler und modaler Harmonisierung?", opts: ["Die tonale verwendet mehr Akkorde", "Die tonale ordnet die Akkorde in einer Spannung/Auflösung-Hierarchie an; die modale erhält eine stabile Farbe", "Die modale verwendet nur Moll-Akkorde", "Die tonale ist moderner"], a: 1, fb: "Tonal = funktionale Hierarchie (T, SD, D) mit obligatorischer Auflösung. Modal = stabile harmonische Farbe – die Akkorde pendeln um die Tonika, ohne sie zwingend anzusteuern." },
{ q: "Wie identifiziert man den charakteristischen Akkord eines Modus für die Harmonisierung?", opts: ["Es ist immer der IV-Akkord", "Es ist der Akkord, der auf der charakteristischen Note des Modus im Vergleich zur Standard-Dur- oder Moll-Tonleiter aufgebaut ist", "Es ist immer der ♭VII-Akkord", "Es ist der erste diatonische Akkord"], a: 1, fb: "Der charakteristische Akkord hebt die charakteristische Note des Modus hervor. Im Dorischen: IV-Dur (große Sexte). Im Phrygischen: ♭II (erniedrigte Sekunde). Im Lydischen: II-Dur (#4). Im Mixolydischen: ♭VII (kleine Septime)." },
{ q: "Welche dieser Progressionen ist modal (nicht tonal)?", opts: ["I – IV – V7 – I", "IIm – V7 – Imaj7", "Im – IV – Im – IV (dorisch)", "I – VI – II – V"], a: 2, fb: "Im – IV – Im – IV (D-Dorisch: Dm – G – Dm – G) ist eine modale Progression – sie pendelt ohne V7→I-Auflösung. Die anderen drei sind klassische tonale Progressionen mit einem aktiven V7 zu I." },
{ q: "Was erhält die modale Farbe in einer Harmonisierung?", opts: ["Immer in Moll spielen", "Den charakteristischen Akkord des Modus regelmäßig verwenden und V7→I vermeiden", "Jede Dissonanz vermeiden", "Auf einem einzigen Akkord bleiben"], a: 1, fb: "Die modale Farbe wird durch zwei Elemente erhalten: die Verwendung des charakteristischen Akkords (der die charakteristische Note enthält) und die Vermeidung von V7→I (die eine tonale Auflösung erzeugen würde)." },
{ q: "Wie klingt modale Musik im Vergleich zu tonaler Musik?", opts: ["Modale Musik 'kommt irgendwo an' wie tonale Musik", "Modale Musik 'bleibt irgendwo' – sie schwebt und färbt, anstatt fortzuschreiten", "Modale Musik ist immer schneller", "Modale Musik verwendet mehr Dissonanzen"], a: 1, fb: "Tonale Musik erzeugt ein Gefühl von Richtung und Ankunft (Spannung → Auflösung). Modale Musik erzeugt ein Gefühl der Schwebe, stabiler Farbe – sie 'ist' irgendwo, anstatt dorthin zu 'gelangen'." },
{ q: "Was ersetzt der charakteristische Akkord des Modus funktional im Modalen?", opts: ["Den Subdominant-Akkord", "Die Dominante V7 – er bringt harmonisches Interesse, ohne eine tonale Auflösung zu erzeugen", "Die Tonika", "Den neapolitanischen Sextakkord"], a: 1, fb: "Der charakteristische Akkord (IV im Dorischen, ♭II im Phrygischen…) ist der harmonische Interessepunkt des Modus – er vermeidet die Eintönigkeit eines einzigen Akkords, aber ohne die Richtungsanziehung von V7." },
{ q: "Welche Progression charakterisiert die Harmonisierung im dorischen Modus?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 1, fb: "Im – IV im Dorischen (z.B. Dm – G in D-Dorisch) ist die fundamentale modale Progression. IV ist durch die große Sexte Dur – das ist die Jazz-Modal-Farbe von So What von Miles Davis." },
{ q: "In D-Dorisch, welcher Akkord ist IV und warum ist er charakteristisch?", opts: ["Gm – er erinnert an das natürliche Moll", "G-Dur – die große Sexte (B naturel) macht ihn zum Dur-Akkord", "G7 – er erzeugt Spannung", "Gdim – er ist instabil"], a: 1, fb: "In D-Dorisch: D E F G A B C. Auf G: G B D = G-Dur. Das B naturel (große Sexte) macht diesen Akkord zu Dur. In D-Moll natürlich wäre IV Gm – dieser Unterschied macht die dorische Farbe aus." },
{ q: "Welchen Akkord sollte man bei der dorischen Harmonisierung vermeiden?", opts: ["IV-Dur (G in D-Dorisch)", "V7 (A7 in D-Dorisch)", "♭III (F in D-Dorisch)", "♭VII (C in D-Dorisch)"], a: 1, fb: "A7 (V7 in D-Dorisch) führt C# ein – den Leitton, den das Dorische nicht hat (C naturel). Dieses C# erzeugt eine tonale Anziehung zu Dm, die die modale Farbe bricht und das Dorische in harmonisches Moll verwandelt." },
{ q: "Welches Stück von Miles Davis ist das dorische Paradebeispiel schlechthin?", opts: ["Kind of Blue — All Blues", "So What (D-Dorisch)", "Round Midnight", "Autumn Leaves"], a: 1, fb: "So What (1959) ist vollständig in D-Dorisch. Miles Davis und Bill Evans bauen die Harmonie auf Dm7–G (Im–IV) auf, ohne jemals eine tonale Auflösung anzusteuern – das ist der Archetypus des modalen Jazz." },
{ q: "Im – IV in der dorischen Harmonisierung erzeugt:", opts: ["Eine Spannung, die nach Auflösung verlangt", "Ein farbiges Pendeln ohne Auflösung", "Eine vollkommene Kadenz", "Eine Bewegung von der Subdominante zur Dominante"], a: 1, fb: "Im – IV im Dorischen (Dm – G) pendelt zwischen zwei Akkorden ohne funktionale Hierarchie. Keine Spannung, die nach Auflösung ruft – es ist eine Farbe, die sich hält, schwebt, atmet." },
{ q: "In G-Dorisch, welcher Akkord ist IV?", opts: ["Cm (C-Moll)", "C-Dur", "Cdim", "C7"], a: 1, fb: "G-Dorisch: G A Bb C D E F. Auf C: C E G = C-Dur. Die große Sexte des Dorischen (E naturel statt Eb) macht diesen IV-Akkord zu Dur – das harmonische Merkmal des dorischen Modus." },
{ q: "Die Bossa Nova verwendet oft das Dorische, weil:", opts: ["Das Dorische ausschließlich brasilianisch ist", "Die große Sexte des Dorischen eine raffinierte Farbe erzeugt, halb dunkel, halb hell, perfekt für die Saudade", "Das Dorische der einfachste der Modi ist", "Die Bossa Nova Dur-Akkorde vermeidet"], a: 1, fb: "Die brasilianische Saudade – süße und helle Melancholie – findet im Dorischen ihren perfekten harmonischen Ausdruck. Die große Sexte verhindert, dass IV dunkel wird (Gm) – er bleibt hell (G) und schafft die Balance zwischen Licht und Schatten." },
{ q: "Was ist die charakteristische Kadenz des phrygischen Modus?", opts: ["V7 – I", "IV – I", "♭II – Im (phrygische Kadenz)", "♭VII – I"], a: 2, fb: "Die phrygische Kadenz ♭II→Im (z.B. F→Em in E-Phrygisch) ist die harmonische DNA des Flamenco. Die absteigende Halbtonbewegung erzeugt eine einzigartige Spannung, die sich von V7→I unterscheidet." },
{ q: "In E-Phrygisch, welcher Akkord ist ♭II?", opts: ["D-Dur", "F-Dur", "Eb-Dur", "B-Dur"], a: 1, fb: "E-Phrygisch: E F G A B C D. ♭II wird auf F aufgebaut: F A C = F-Dur. Die erniedrigte Sekunde des Phrygischen (F statt F#) erzeugt diesen sehr charakteristischen Akkord." },
{ q: "Warum ist die Bewegung F→Em (in E-Phrygisch) so ausdrucksstark?", opts: ["F ist eine Quarte von Em", "Es ist eine absteigende Halbtonbewegung – das engste aller Intervalle", "F ist die Dominante von Em", "Es ist ein Tritonus"], a: 1, fb: "F→E ist ein absteigender Halbton – das kleinste und spannungsreichste Intervall. Diese ♭II→Im-Bewegung erzeugt eine starke Anziehung durch chromatische Nähe, sehr anders als die tonale Auflösung V7→I." },
{ q: "Welches Musikgenre verwendet hauptsächlich die phrygische Kadenz?", opts: ["Amerikanischer Blues", "Modaler Jazz", "Spanischer Flamenco", "Gospel"], a: 2, fb: "Der spanische Flamenco basiert auf der phrygischen Kadenz ♭II→Im und ihren Varianten. Die dunkle, mediterrane Farbe des Phrygischen – mit seiner erniedrigten Sekunde – ist die klangliche Identität der andalusischen Musik." },
{ q: "Bei der phrygischen Harmonisierung, welchen Akkord sollte man vermeiden?", opts: ["♭II (F in E-Phrygisch)", "Im (Em)", "V7 (B7 in E-Phrygisch)", "♭VII (D in E-Phrygisch)"], a: 2, fb: "B7 (V7 in E-Phrygisch) führt D# ein – einen Leitton, der dem Phrygischen fremd ist (D naturel). Dieses D# erzeugt eine tonale Auflösung zu Em und löscht die phrygische Farbe aus." },
{ q: "In A-Phrygisch, welcher Akkord ist ♭II?", opts: ["G-Dur", "Bb-Dur", "B-Dur", "Ab-Dur"], a: 1, fb: "A-Phrygisch: A Bb C D E F G. ♭II wird auf Bb aufgebaut: Bb D F = Bb-Dur. Die erniedrigte Sekunde (Bb statt B) erzeugt diesen charakteristischen Akkord des Phrygischen." },
{ q: "Die Farbe 'dunkel und mediterran' ist mit welchem Modus verbunden?", opts: ["Dorisch", "Lydisch", "Phrygisch", "Äolisch"], a: 2, fb: "Das Phrygische ist der Modus des Mittelmeers – seine erniedrigte Sekunde und die Kadenz ♭II→Im erzeugen eine dunkle, intensive, dramatische Farbe. Das ist die klangliche Identität des Flamenco und der spanischen Musik." },
{ q: "Welche Progression charakterisiert die Harmonisierung im lydischen Modus?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – II – I", "I – ♭VII – IV – I"], a: 2, fb: "I – II im Lydischen (z.B. F – G in F-Lydisch) ist die charakteristische Progression. II ist wegen des #4 Dur – eine aufsteigende Sekundenbewegung Dur–Dur, die in der Standard-Durtonleiter unmöglich ist (wo II Moll ist)." },
{ q: "Warum ist der II-Akkord im lydischen Modus Dur?", opts: ["Weil das Lydische ein Moll-Modus ist", "Weil der #4 (übermäßige Quarte) des Lydischen im II-Akkord enthalten ist", "Weil II im Modalen immer Dur ist", "Weil das Lydische vom IV. Grad abgeleitet ist"], a: 1, fb: "In F-Lydisch: F G A B C D E. Auf G (II): G B D = G-Dur. Das B naturel (#4 des Lydischen) ist die Terz von G – es macht den II-Akkord zu Dur. In Standard-F-Dur wäre II Gm (mit Bb)." },
{ q: "Welcher Filmkomponist verwendet das Lydische ausgiebig, um das Wunderbare zu evozieren?", opts: ["Ennio Morricone", "John Williams", "Hans Zimmer", "Bernard Herrmann"], a: 1, fb: "John Williams verwendet das Lydische in E.T., Superman und seinen magischen Musiken. Das #4 erzeugt eine helle und traumhafte Farbe – die übermäßige Quarte vermeidet die perfekte Stabilität der Durtonleiter und lässt die Musik 'schweben'." },
{ q: "In F-Lydisch, welchen Akkord sollte man vermeiden, um die Farbe zu bewahren?", opts: ["G-Dur (II)", "Bb (IV von Standard-F-Dur)", "Am (IIIm)", "C (V)"], a: 1, fb: "Bb führt genau die Note wieder ein, die das Lydische durch B naturel (#4) ersetzt. Bb zu spielen löscht die lydische Farbe sofort aus und lässt eine Standard-Durtonleiter hören." },
{ q: "In C-Lydisch, welcher Akkord ist II?", opts: ["Dm", "D-Dur", "Ddim", "D7"], a: 1, fb: "C-Lydisch: C D E F# G A B. Auf D: D F# A = D-Dur. Das F# (#4 des Lydischen) ist die Terz von D – es macht den II-Akkord zu Dur und enthüllt den Modus für das Ohr." },
{ q: "Die Farbe 'hell und traumhaft' ist mit welchem Modus verbunden?", opts: ["Äolisch", "Phrygisch", "Mixolydisch", "Lydisch"], a: 3, fb: "Das Lydische mit seinem #4 erzeugt eine helle und traumhafte Farbe. Die übermäßige Quarte vermeidet die perfekte Stabilität der Durtonleiter – sie schwebt, sie leuchtet. Es ist der Modus des Staunens und der Magie." },
{ q: "Das Hauptthema der Simpsons beginnt mit einem:", opts: ["Phrygischen Sprung (♭2)", "Aufsteigenden lydischen Tritonus (Grundton zu #4)", "Dominantseptakkord", "Äolischen Schritt (♭VII)"], a: 1, fb: "Das Simpsons-Thema beginnt mit einem aufsteigenden Sprung zum lydischen #4 – dem Tritonus F→B in F-Lydisch. Dieses leicht merkwürdige #4 erzeugt diese so unverwechselbare Farbe." },
{ q: "Welche Progression ist typisch für den mixolydischen Modus?", opts: ["Im – IV – Im", "Im – ♭VI – ♭VII – Im", "I – ♭VII – IV – I", "I – II – I"], a: 2, fb: "I – ♭VII – IV – I (z.B. G – F – C – G in G-Mixolydisch) ist die Rock-/Blues-Progression schlechthin. Das ♭VII (F) erzeugt eine Rückwärtsbewegung ohne Leittonauflösung." },
{ q: "In G-Mixolydisch, welcher Akkord ist ♭VII?", opts: ["F#-Dur", "F-Moll", "F-Dur", "Fdim"], a: 2, fb: "G-Mixolydisch: G A B C D E F. ♭VII wird auf F aufgebaut: F A C = F-Dur. Die kleine Septime (F statt F#) macht diesen Akkord zu Dur – das ist das harmonische Merkmal des Mixolydischen." },
{ q: "Warum vermeidet man V7 bei der mixolydischen Harmonisierung?", opts: ["V7 ist zu einfach", "V7 führt den Leitton (F# in G-Mixolydisch) ein, der dem Modus fehlt, und erzeugt eine Auflösung zu G", "V7 erzeugt Quintenparallelen", "V7 ändert den Modus in Lydisch"], a: 1, fb: "In G-Mixolydisch ist F die ♭7 (charakteristische Note). D7 (V7) führt F# ein – den Leitton, der im Modus nicht existiert. Dieses F# erzeugt eine Spannung zu G (tonale Auflösung), die die zyklische Farbe des Mixolydischen bricht." },
{ q: "Welcher Musikstil basiert harmonisch auf dem mixolydischen Modus?", opts: ["Barockmusik", "Spanischer Flamenco", "Blues und Rock", "Romantische Musik"], a: 2, fb: "Blues und Rock verwenden hauptsächlich das Mixolydische. Der I7-Akkord des Blues (mit kleiner Septime) ist der Akkord des Mixolydischen. Die I7–IV7–V7-Progression des Blues ist grundlegend mixolydisch." },
{ q: "Norwegian Wood der Beatles steht in welchem Modus?", opts: ["Dorisch", "Phrygisch", "Äolisch", "Mixolydisch"], a: 3, fb: "Norwegian Wood (1965) steht in E-Mixolydisch. Die kleine Septime (D naturel statt D#) in Melodie und Harmonie verleiht diese charakteristische modale Farbe – Dur, aber unaufgelöst." },
{ q: "In D-Mixolydisch, welcher Akkord ist ♭VII?", opts: ["C#-Dur", "C-Moll", "C-Dur", "Cdim"], a: 2, fb: "D-Mixolydisch: D E F# G A B C. Auf C: C E G = C-Dur. Die kleine Septime (C statt C#) ist die charakteristische Note des Mixolydischen – und dieser ♭VII-Dur-Akkord ist seine harmonische Signatur." },
{ q: "Die Farbe 'energisch und zyklisch ohne Auflösung' ist mit welchem Modus verbunden?", opts: ["Ionisch", "Dorisch", "Äolisch", "Mixolydisch"], a: 3, fb: "Das Mixolydische erzeugt eine immerwährende Energie – die Progression I–♭VII–IV–I dreht sich, ohne wirklich 'anzukommen'. Die kleine Septime verhindert die Auflösung zu I, während die Dur-Farbe erhalten bleibt. Das ist das Wesen von Blues und Rock." },
{ q: "Welche Progression ist typisch für den äolischen Modus?", opts: ["Im – IV – Im", "Im – ♭II – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 3, fb: "Im – ♭VI – ♭VII – Im (z.B. Am – F – G – Am in A-Äolisch) ist die verbreitetste natürliche Moll-Progression in Pop und Rock. Sie pendelt ohne Leitton und erzeugt eine sanfte, natürliche Melancholie." },
{ q: "In A-Äolisch, warum ist ♭VII G-Dur?", opts: ["Weil G die Quinte von C ist", "Weil in A-Äolisch (A B C D E F G) der Akkord auf G: G B D = G-Dur ist", "Weil G im Moll immer Dur ist", "Weil G die parallele Tonika ist"], a: 1, fb: "A-Äolisch: A B C D E F G. Auf G (♭VII): G B D = G-Dur. Das B naturel in G ergibt einen hellen Dur-Akkord auf ♭VII – er verhindert, dass die Farbe zu dunkel wird." },
{ q: "Wie unterscheidet sich das Äolische harmonisch vom harmonischen Moll?", opts: ["Das Äolische hat eine große Terz", "Das Äolische hat keinen Leitton – sein V ist Vm (Moll), nicht V7", "Das Äolische hat keinen IV. Grad", "Das Äolische verwendet den neapolitanischen Akkord"], a: 1, fb: "Im Äolischen: V = Em (Moll, ohne Leitton). Im harmonischen Moll: V = E7 (mit G# als Leitton). Dieser Leitton erzeugt die tonale Auflösung. Das Äolische vermeidet diese Spannung – natürlicher, weniger gerichtet." },
{ q: "Die Progression Am – F – G – Am ist typisch für:", opts: ["Tonal (harmonisches Moll)", "Modal (natürliches Äolisch)", "Tonal (Dur)", "Pentatonisch"], a: 1, fb: "Am – F – G – Am ist rein äolisch – ohne E7 (V7). G (♭VII) und F (♭VI) sind charakteristisch für natürliches Moll/Äolisch. Das ist die Progression von House of the Rising Sun, Losing My Religion..." },
{ q: "In A-Äolisch, welches Problem stellt E7 (V7) dar?", opts: ["Er ist zu tief", "Er führt G# ein – den Leitton, der dem Äolischen fehlt (G naturel) – und erzeugt eine tonale Auflösung zu Am", "Er erzeugt Quintenparallelen", "Er erzwingt den Wechsel ins Lydische"], a: 1, fb: "E7 enthält G# – den Leitton, den das Äolische nicht hat (G naturel). Dieses G# verlangt zwingend nach Auflösung zu A, verwandelt den Modus in harmonisches Moll und bricht die natürliche Melancholie des Äolischen." },
{ q: "In E-Äolisch, welcher Akkord ist ♭VII?", opts: ["D#-Dur", "D-Moll", "D-Dur", "Ddim"], a: 2, fb: "E-Äolisch: E F# G A B C D. Auf D: D F# A = D-Dur. Das D naturel (♭7) macht den ♭VII-Akkord zu Dur – seine Anwesenheit charakterisiert harmonisch den äolischen Modus und unterscheidet seine Farbe vom harmonischen Moll." },
{ q: "Stairway to Heaven von Led Zeppelin verwendet hauptsächlich:", opts: ["Den lydischen Modus", "Den mixolydischen Modus", "Den äolischen Modus (natürliches Moll)", "Den phrygischen Modus"], a: 2, fb: "Stairway to Heaven basiert auf A-Moll natürlich (A-Äolisch) – die charakteristische Progression Am – G – F. Die introspektive Melancholie des natürlichen Moll ohne Leitton ist typisch äolisch." },
{ q: "Ein IV-Dur-Akkord in einem Moll-Kontext deutet wahrscheinlich auf welchen Modus hin?", opts: ["Harmonisches Moll", "Dorischer Modus", "Phrygischer Modus", "Lokrische Modus"], a: 1, fb: "IV-Dur in einem Moll-Kontext ist die harmonische Signatur des Dorischen. In natürlichem Moll (Äolisch) wäre IV Moll. Das Vorhandensein eines IV-Dur (z.B. G in D-Moll) signalisiert die dorische große Sexte." },
{ q: "Ein ♭II-Akkord in einem Moll-Kontext deutet wahrscheinlich auf welchen Modus hin?", opts: ["Dorischer Modus", "Harmonisches Moll", "Phrygischer Modus", "Äolischer Modus"], a: 2, fb: "♭II in einem Moll-Kontext ist die Signatur des Phrygischen. Der auf der erniedrigten Sekunde aufgebaute Akkord (z.B. F in E-Phrygisch) ist einzigartig für diesen Modus – kein anderer Moll-Modus besitzt ihn von Natur aus." },
{ q: "Ein ♭VII-Dur-Akkord in einem Dur-Kontext deutet wahrscheinlich auf welchen Modus hin?", opts: ["Lydischer Modus", "Ionischer Modus", "Mixolydischer Modus", "Dorischer Modus"], a: 2, fb: "♭VII-Dur in einem Dur-Kontext ist die Signatur des Mixolydischen. In der Standard-Durtonleiter existiert ♭VII nicht (der VII. Grad ist vermindert). Das Vorhandensein von ♭VII-Dur (z.B. F in G-Dur) signalisiert die mixolydische kleine Septime." },
{ q: "Was ist der Unterschied zwischen Im–IV (dorisch) und Im–Vm (äolisch)?", opts: ["Im–IV ist dynamisch stärker", "Im–IV verwendet IV-Dur (Dorisch, große Sexte); Im–Vm verwendet V-Moll (Äolisch, kleine Sexte)", "Im–Vm ist eine vollkommene Kadenz", "Es gibt keinen Unterschied"], a: 1, fb: "Der Unterschied liegt in der Sexte des Modus. Dorisch: große Sexte → IV ist Dur (G in D-Dorisch). Äolisch: kleine Sexte → Vm ist Moll (Em in A-Äolisch). Diese beiden Akkorde erzeugen eine grundlegend andere Farbe." },
{ q: "Welche Progression ist unter diesen Optionen die tonalste?", opts: ["Dm – G – Dm (Im–IV dorisch)", "Em – F – Em (♭II phrygisch)", "Am – Dm – E7 – Am", "G – F – C – G (mixolydisch)"], a: 2, fb: "Am – Dm – E7 – Am enthält E7 (V7), das G# (Leitton) einführt und tonal zu Am auflöst – das ist harmonisches Moll, kein Modal. Die anderen drei vermeiden V7→I und erhalten eine modale Farbe." },
{ q: "Um eine Rock-Melodie mit einem Riff G – F – C – G zu harmonisieren, ist der Modus:", opts: ["Ionisch (G-Dur)", "Dorisch", "Mixolydisch (G-Mixolydisch)", "Lydisch"], a: 2, fb: "G – F – C – G = I – ♭VII – IV – I in G-Mixolydisch. Das F (♭VII) existiert nicht in Standard-G-Dur (dort ist F# natürlich). Das Vorhandensein von F naturel bestätigt G-Mixolydisch – den Modus des Blues und des Rock." },
{ q: "Um eine Flamenco-Melodie zu harmonisieren, welchen Modus wählt man?", opts: ["Dorisch (Im–IV)", "Phrygisch (Im–♭II)", "Mixolydisch (I–♭VII)", "Äolisch (Im–♭VI–♭VII)"], a: 1, fb: "Der Flamenco verwendet den phrygischen Modus. Die Kadenz ♭II→Im (z.B. F→Em in E-Phrygisch) ist die harmonische DNA des Flamenco – die dunkle, mediterrane Farbe kommt direkt von der erniedrigten Sekunde." },
{ q: "So What von Miles Davis (1959) ist harmonisiert mit:", opts: ["Phrygischen Akkorden", "Dorischen Akkorden (Dm7–G)", "Mixolydischen Akkorden", "Lydischen Akkorden"], a: 1, fb: "So What steht in D-Dorisch. Miles Davis verwendet das Pendeln Dm7 – G (Im – IV im Dorischen) – kein V7→I. Die Jazz-Modal-Farbe entsteht durch diese einfache Schwingung ohne tonale Auflösung — das Archetyp des modalen Jazz." },
];

const questionsIt: Question[] = [{ q: "Nell'armonizzazione modale, qual è l'obiettivo principale degli accordi?", opts: ["Creare tensione e risoluzione (SD→D→T)", "Mantenere e colorare il modo senza risoluzione obbligatoria", "Finire sempre su V7→I", "Utilizzare i 7 accordi diatonici in modo uguale"], a: 1, fb: "In modale, gli accordi devono preservare il colore del modo — non creare tensione tonale. L'oscillazione tra Im e un accordo caratteristico è sufficiente; una risoluzione V7→I distruggerebbe l'identità modale." },
{ q: "Perché bisogna evitare V7→I in un contesto modale?", opts: ["V7 è troppo dissonante", "V7 introduce la sensibile assente dal modo, creando una risoluzione tonale che cancella il colore modale", "V7 non esiste nella musica modale", "V7 è riservato ai modi maggiori"], a: 1, fb: "La sensibile in V7 crea una tensione irresistibile verso I — è il motore tonale. In modale, si vuole evitare questa attrazione per mantenere il colore fluttuante del modo." },
{ q: "Qual è la differenza fondamentale tra un'armonizzazione tonale e modale?", opts: ["Quella tonale utilizza più accordi", "Quella tonale organizza gli accordi in una gerarchia tensione/risoluzione; quella modale mantiene un colore stabile", "Quella modale usa solo accordi minori", "Quella tonale è più moderna"], a: 1, fb: "Tonale = gerarchia funzionale (T, SD, D) con risoluzione obbligatoria. Modale = colore armonico stabile — gli accordi oscillano attorno alla tonica senza chiamarla in modo imperativo." },
{ q: "Come identificare l'accordo caratteristico di un modo per l'armonizzazione?", opts: ["È sempre l'accordo IV", "È l'accordo costruito sulla nota distintiva del modo rispetto alla scala maggiore o minore standard", "È sempre l'accordo ♭VII", "È il primo accordo diatonico"], a: 1, fb: "L'accordo caratteristico mette in valore la nota distintiva del modo. In dorico: IV maggiore (6a maggiore). In frigio: ♭II (2a bemolle). In lidio: II maggiore (#4). In misolidio: ♭VII (7a minore)." },
{ q: "Quale di queste progressioni è modale (non tonale)?", opts: ["I – IV – V7 – I", "IIm – V7 – Imaj7", "Im – IV – Im – IV (dorico)", "I – VI – II – V"], a: 2, fb: "Im – IV – Im – IV (D dorico: Dm – G – Dm – G) è una progressione modale — oscilla senza risoluzione V7→I. Le altre 3 sono progressioni tonali classiche con un V7 attivo verso I." },
{ q: "Cosa mantiene il colore modale in un'armonizzazione?", opts: ["Suonare sempre in minore", "Utilizzare regolarmente l'accordo caratteristico del modo ed evitare V7→I", "Evitare qualsiasi dissonanza", "Restare su un solo accordo"], a: 1, fb: "Il colore modale è mantenuto da due elementi: l'utilizzo dell'accordo caratteristico (che contiene la nota distintiva) e l'evitamento di V7→I (che creerebbe una risoluzione tonale)." },
{ q: "Come suona la musica modale rispetto alla musica tonale?", opts: ["Quella modale 'arriva da qualche parte' come quella tonale", "Quella modale 'rimane da qualche parte' — fluttua e colora piuttosto che progredire", "Quella modale è sempre più veloce", "Quella modale usa più dissonanze"], a: 1, fb: "La musica tonale crea un senso di direzione e arrivo (tensione → risoluzione). La musica modale crea un senso di sospensione, di colore stabile — 'è' da qualche parte piuttosto che 'arrivarci'." },
{ q: "In modale, cosa sostituisce funzionalmente l'accordo caratteristico del modo?", opts: ["L'accordo di sottodominante", "La dominante V7 — apporta interesse armonico senza creare risoluzione tonale", "La tonica", "L'accordo di sesta napoletana"], a: 1, fb: "L'accordo caratteristico (IV in dorico, ♭II in frigio…) è il punto di interesse armonico del modo — evita la monotonia di un accordo unico, ma senza l'attrazione direzionale di V7." },
{ q: "Quale progressione caratterizza l'armonizzazione nel modo dorico?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 1, fb: "Im – IV in dorico (es. Dm – G in D dorico) è la progressione modale fondamentale. IV è maggiore grazie alla 6a maggiore — è il colore jazz-modale di So What di Miles Davis." },
{ q: "In D dorico, quale accordo è IV e perché è caratteristico?", opts: ["Gm — richiama il minore naturale", "G maggiore — la 6a maggiore (B naturale) lo rende maggiore", "G7 — crea tensione", "Gdim — è instabile"], a: 1, fb: "In D dorico: D E F G A B C. Su G: G B D = G maggiore. Il B naturale (6a maggiore) rende questo accordo maggiore. In D minore naturale, IV sarebbe Gm — è questa differenza a fare il colore dorico." },
{ q: "Quale accordo bisogna evitare nell'armonizzazione dorica?", opts: ["IV maggiore (G in D dorico)", "V7 (A7 in D dorico)", "♭III (F in D dorico)", "♭VII (C in D dorico)"], a: 1, fb: "A7 (V7 in D dorico) introduce C# — la sensibile che il dorico non ha (C naturale). Questo C# crea un'attrazione tonale verso Dm che distrugge il colore modale e trasforma il dorico in minore armonico." },
{ q: "Quale brano di Miles Davis è l'esempio modale dorico per eccellenza?", opts: ["Kind of Blue — All Blues", "So What (D dorico)", "Round Midnight", "Autumn Leaves"], a: 1, fb: "So What (1959) è interamente in D dorico. Miles Davis e Bill Evans costruiscono l'armonia su Dm7–G (Im–IV), senza mai richiamare una risoluzione tonale — è l'archetipo del jazz modale." },
{ q: "In armonizzazione dorica, Im – IV crea:", opts: ["Una tensione che richiede risoluzione", "Un'oscillazione colorata senza risoluzione", "Una cadenza perfetta", "Un movimento di sottodominante verso dominante"], a: 1, fb: "Im – IV in dorico (Dm – G) oscilla tra due accordi senza gerarchia funzionale. Nessuna tensione che chiama risoluzione — è un colore che si mantiene, fluttua, respira." },
{ q: "In G dorico, quale accordo è IV?", opts: ["Cm (C minore)", "C maggiore", "Cdim", "C7"], a: 1, fb: "G dorico: G A Bb C D E F. Su C: C E G = C maggiore. La 6a maggiore del dorico (E naturale invece di Eb) rende questo accordo IV maggiore — il marchio armonico del modo dorico." },
{ q: "La Bossa Nova usa spesso il dorico perché:", opts: ["Il dorico è esclusivamente brasiliano", "La 6a maggiore del dorico crea un colore sofisticato a metà tra scuro e luminoso, perfetto per la saudade", "Il dorico è il più semplice dei modi", "La Bossa Nova evita gli accordi maggiori"], a: 1, fb: "La saudade brasiliana — malinconia dolce e luminosa — trova nel dorico la sua espressione armonica perfetta. La 6a maggiore impedisce a IV di essere scuro (Gm) — rimane luminoso (G), creando l'equilibrio tra ombra e luce." },
{ q: "Qual è la cadenza caratteristica del modo frigio?", opts: ["V7 – I", "IV – I", "♭II – Im (cadenza frigia)", "♭VII – I"], a: 2, fb: "La cadenza frigia ♭II→Im (es. F→Em in E frigio) è il DNA armonico del flamenco. Il movimento discendente per semitono crea una tensione unica diversa da V7→I." },
{ q: "In E frigio, quale accordo è ♭II?", opts: ["D maggiore", "F maggiore", "Eb maggiore", "B maggiore"], a: 1, fb: "E frigio: E F G A B C D. Il ♭II è costruito su F: F A C = F maggiore. La 2a bemolle del frigio (F invece di F#) crea questo accordo molto caratteristico." },
{ q: "Perché il movimento F→Em (in E frigio) è così espressivo?", opts: ["F è una quarta di Em", "È un movimento discendente per semitono — il più stretto di tutti gli intervalli", "F è la dominante di Em", "È un tritono"], a: 1, fb: "F→E è un semitono discendente — l'intervallo più piccolo e più teso. Questo movimento ♭II→Im crea un'attrazione potente per prossimità cromatica, molto diversa dalla risoluzione tonale V7→I." },
{ q: "Quale genere musicale utilizza principalmente la cadenza frigia?", opts: ["Blues americano", "Jazz modale", "Flamenco spagnolo", "Gospel"], a: 2, fb: "Il flamenco spagnolo è fondato sulla cadenza frigia ♭II→Im e le sue variazioni. Il colore scuro e mediterraneo del frigio — con la sua 2a bemolle — è l'identità sonora della musica andalusa." },
{ q: "Nell'armonizzazione frigia, quale accordo bisogna evitare?", opts: ["♭II (F in E frigio)", "Im (Em)", "V7 (B7 in E frigio)", "♭VII (D in E frigio)"], a: 2, fb: "B7 (V7 in E frigio) introduce D# — una sensibile estranea al frigio (D naturale). Questo D# crea una risoluzione tonale verso Em, cancellando il colore frigio." },
{ q: "In A frigio, quale accordo è ♭II?", opts: ["G maggiore", "Bb maggiore", "B maggiore", "Ab maggiore"], a: 1, fb: "A frigio: A Bb C D E F G. Il ♭II è costruito su Bb: Bb D F = Bb maggiore. La 2a bemolle (Bb invece di B) crea questo accordo caratteristico del frigio." },
{ q: "Il colore 'scuro e mediterraneo' è associato a quale modo?", opts: ["Dorico", "Lidio", "Frigio", "Eolico"], a: 2, fb: "Il frigio è il modo del Mediterraneo — la sua 2a bemolle e la cadenza ♭II→Im creano un colore scuro, intenso, drammatico. È l'identità sonora del flamenco e della musica spagnola." },
{ q: "Quale progressione caratterizza l'armonizzazione nel modo lidio?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – II – I", "I – ♭VII – IV – I"], a: 2, fb: "I – II in lidio (es. F – G in F lidio) è la progressione caratteristica. II è maggiore grazie al #4 — un movimento di seconda ascendente maggiore–maggiore impossibile nella scala maggiore standard (dove II è minore)." },
{ q: "Perché l'accordo II è maggiore nel modo lidio?", opts: ["Perché il lidio è un modo minore", "Perché il #4 (4a aumentata) del lidio è nell'accordo II", "Perché II è sempre maggiore in modale", "Perché il lidio deriva dal IV grado"], a: 1, fb: "In F lidio: F G A B C D E. Su G (II): G B D = G maggiore. Il B naturale (#4 del lidio) è la terza di G — rende l'accordo II maggiore. In F maggiore standard, II sarebbe Gm (con Bb)." },
{ q: "Quale compositore di musiche da film usa abbondantemente il lidio per evocare il meraviglioso?", opts: ["Ennio Morricone", "John Williams", "Hans Zimmer", "Bernard Herrmann"], a: 1, fb: "John Williams usa il lidio in E.T., Superman e nelle sue musiche magiche. Il #4 crea un colore luminoso e onirico — la 4a aumentata evita la stabilità perfetta della scala maggiore e fa 'fluttuare' la musica." },
{ q: "In F lidio, quale accordo bisogna evitare per preservare il colore?", opts: ["G maggiore (II)", "Bb (IV di F maggiore standard)", "Am (IIIm)", "C (V)"], a: 1, fb: "Bb reintroduce esattamente la nota che il lidio sostituisce con B naturale (#4). Suonare Bb cancella istantaneamente il colore lidio e fa sentire una scala maggiore standard." },
{ q: "In C lidio, quale accordo è II?", opts: ["Dm", "D maggiore", "Ddim", "D7"], a: 1, fb: "C lidio: C D E F# G A B. Su D: D F# A = D maggiore. Il F# (#4 del lidio) è la terza di D — rende l'accordo II maggiore e rivela il modo all'orecchio." },
{ q: "Il colore 'luminoso e onirico' è associato a quale modo?", opts: ["Eolico", "Frigio", "Misolidio", "Lidio"], a: 3, fb: "Il lidio con il suo #4 crea un colore luminoso e onirico. La 4a aumentata evita la stabilità perfetta della scala maggiore — fluttua, brilla. È il modo dello stupore e della magia." },
{ q: "Il tema principale dei Simpson inizia con:", opts: ["Un salto frigio (♭2)", "Un tritono ascendente lidio (fondamentale verso #4)", "Un accordo di dominante", "Un movimento eolico (♭VII)"], a: 1, fb: "Il tema dei Simpson inizia con un salto ascendente verso il #4 lidio — il tritono F→B in F lidio. È questo #4 leggermente bizzarro a creare quel colore così riconoscibile." },
{ q: "Quale progressione è tipica del modo misolidio?", opts: ["Im – IV – Im", "Im – ♭VI – ♭VII – Im", "I – ♭VII – IV – I", "I – II – I"], a: 2, fb: "I – ♭VII – IV – I (es. G – F – C – G in G misolidio) è la progressione rock/blues per eccellenza. Il ♭VII (F) crea un movimento di ritorno senza risoluzione di sensibile." },
{ q: "In G misolidio, quale accordo è ♭VII?", opts: ["F# maggiore", "F minore", "F maggiore", "Fdim"], a: 2, fb: "G misolidio: G A B C D E F. Il ♭VII è costruito su F: F A C = F maggiore. La 7a minore (F invece di F#) rende questo accordo maggiore — è il marchio armonico del misolidio." },
{ q: "Perché si evita V7 nell'armonizzazione misolidia?", opts: ["V7 è troppo semplice", "V7 introduce la sensibile (F# in G misolidio) assente dal modo, creando una risoluzione verso G", "V7 crea una quinta parallela", "V7 cambia il modo in lidio"], a: 1, fb: "In G misolidio, F è ♭7 (nota caratteristica). D7 (V7) introduce F# — la sensibile che non esiste nel modo. Questo F# crea una tensione verso G (risoluzione tonale) che distrugge il colore ciclico del misolidio." },
{ q: "Quale stile musicale è armonicamente basato sul modo misolidio?", opts: ["Musica barocca", "Flamenco spagnolo", "Blues e rock", "Musica romantica"], a: 2, fb: "Il blues e il rock usano principalmente il misolidio. L'accordo I7 del blues (con 7a minore) è l'accordo del misolidio. La progressione I7–IV7–V7 del blues è fondamentalmente misolidia." },
{ q: "Norwegian Wood dei Beatles è in quale modo?", opts: ["Dorico", "Frigio", "Eolico", "Misolidio"], a: 3, fb: "Norwegian Wood (1965) è in E misolidio. La 7a minore (D naturale invece di D#) nella melodia e nell'armonia dà quel caratteristico colore modale — maggiore ma non risolto." },
{ q: "In D misolidio, quale accordo è ♭VII?", opts: ["C# maggiore", "C minore", "C maggiore", "Cdim"], a: 2, fb: "D misolidio: D E F# G A B C. Su C: C E G = C maggiore. La 7a minore (C invece di C#) è la nota caratteristica del misolidio — e questo accordo ♭VII maggiore ne è la firma armonica." },
{ q: "Il colore 'energico e ciclico senza risoluzione' è associato a quale modo?", opts: ["Ionico", "Dorico", "Eolico", "Misolidio"], a: 3, fb: "Il misolidio crea un'energia perpetua — la progressione I–♭VII–IV–I gira senza mai 'arrivare' davvero. La 7a minore impedisce la risoluzione verso I pur mantenendo il colore maggiore. È l'essenza del blues e del rock." },
{ q: "Quale progressione è tipica del modo eolico?", opts: ["Im – IV – Im", "Im – ♭II – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 3, fb: "Im – ♭VI – ♭VII – Im (es. Am – F – G – Am in A eolico) è la progressione minore naturale più diffusa nel pop e nel rock. Oscilla senza sensibile, creando una malinconia dolce e naturale." },
{ q: "In A eolico, perché ♭VII è G maggiore?", opts: ["Perché G è la quinta di C", "Perché in A eolico (A B C D E F G), l'accordo su G è G B D = G maggiore", "Perché G è sempre maggiore in minore", "Perché G è la tonica relativa"], a: 1, fb: "A eolico: A B C D E F G. Su G (♭VII): G B D = G maggiore. Il B naturale in G dà un accordo maggiore luminoso sul ♭VII — è lui che impedisce al colore di essere troppo scuro." },
{ q: "Come si distingue armonicamente l'eolico dal minore armonico?", opts: ["L'eolico ha una terza maggiore", "L'eolico non ha sensibile — il suo V è Vm (minore), non V7", "L'eolico non ha il IV grado", "L'eolico usa l'accordo napoletano"], a: 1, fb: "In eolico, V = Em (minore, senza sensibile). In minore armonico, V = E7 (con G# sensibile). Questa sensibile crea la risoluzione tonale. L'eolico evita questa tensione — più naturale, meno diretto." },
{ q: "La progressione Am – F – G – Am è tipicamente:", opts: ["Tonale (minore armonico)", "Modale (eolico naturale)", "Tonale (maggiore)", "Pentatonica"], a: 1, fb: "Am – F – G – Am è puramente eolica — senza E7 (V7). G (♭VII) e F (♭VI) sono caratteristici del minore naturale/eolico. È la progressione di House of the Rising Sun, Losing My Religion..." },
{ q: "In A eolico, quale problema pone E7 (V7)?", opts: ["È troppo grave", "Introduce G# — la sensibile assente dall'eolico — creando una risoluzione tonale verso Am", "Crea una quinta parallela", "Forza il passaggio in lidio"], a: 1, fb: "E7 contiene G# — la sensibile che l'eolico non ha (G naturale). Questo G# chiama imperativamente la risoluzione verso A, trasformando il modo in minore armonico e rompendo la malinconia naturale dell'eolico." },
{ q: "In E eolico, quale accordo è ♭VII?", opts: ["D# maggiore", "D minore", "D maggiore", "Ddim"], a: 2, fb: "E eolico: E F# G A B C D. Su D: D F# A = D maggiore. Il D naturale (♭7) rende l'accordo ♭VII maggiore — la sua presenza caratterizza armonicamente il modo eolico e distingue il suo colore dal minore armonico." },
{ q: "Stairway to Heaven dei Led Zeppelin utilizza principalmente:", opts: ["Il modo lidio", "Il modo misolidio", "Il modo eolico (minore naturale)", "Il modo frigio"], a: 2, fb: "Stairway to Heaven si basa su A minore naturale (A eolico) — la caratteristica progressione Am – G – F. La malinconia introspettiva del minore naturale senza sensibile è tipicamente eolica." },
{ q: "Un accordo IV maggiore in un contesto minore indica probabilmente quale modo?", opts: ["Minore armonico", "Modo dorico", "Modo frigio", "Modo locrio"], a: 1, fb: "IV maggiore in un contesto minore è la firma armonica del dorico. In minore naturale (eolico), IV sarebbe minore. La presenza di un IV maggiore (es. G in D minore) segnala la 6a maggiore dorica." },
{ q: "Un accordo ♭II in un contesto minore indica probabilmente quale modo?", opts: ["Modo dorico", "Minore armonico", "Modo frigio", "Modo eolico"], a: 2, fb: "♭II in un contesto minore è la firma del frigio. L'accordo costruito sulla 2a bemolle (es. F in E frigio) è unico di questo modo — nessun altro modo minore lo possiede naturalmente." },
{ q: "Un accordo ♭VII maggiore in un contesto maggiore indica probabilmente quale modo?", opts: ["Modo lidio", "Modo ionico", "Modo misolidio", "Modo dorico"], a: 2, fb: "♭VII maggiore in un contesto maggiore è la firma del misolidio. Nella scala maggiore standard, ♭VII non esiste (il VII grado è diminuito). La presenza di ♭VII maggiore (es. F in G maggiore) segnala la 7a minore misolidia." },
{ q: "Qual è la differenza tra Im–IV (dorico) e Im–Vm (eolico)?", opts: ["Im–IV è più forte dinamicamente", "Im–IV usa IV maggiore (dorico, 6a maggiore); Im–Vm usa V minore (eolico, 6a minore)", "Im–Vm è una cadenza perfetta", "Non c'è differenza"], a: 1, fb: "La differenza è la 6a del modo. Dorico: 6a maggiore → IV è maggiore (G in D dorico). Eolico: 6a minore → Vm è minore (Em in A eolico). Questi due accordi creano un colore radicalmente diverso." },
{ q: "Quale progressione è la più tonale tra queste opzioni?", opts: ["Dm – G – Dm (Im–IV dorico)", "Em – F – Em (♭II frigio)", "Am – Dm – E7 – Am", "G – F – C – G (misolidio)"], a: 2, fb: "Am – Dm – E7 – Am contiene E7 (V7) che introduce G# (sensibile) e risolve tonalmente verso Am — è minore armonico, non modale. Le altre 3 evitano V7→I e mantengono un colore modale." },
{ q: "Per armonizzare una melodia rock con un riff G – F – C – G, il modo è:", opts: ["Ionico (G maggiore)", "Dorico", "Misolidio (G misolidio)", "Lidio"], a: 2, fb: "G – F – C – G = I – ♭VII – IV – I in G misolidio. Il F (♭VII) non esiste in G maggiore standard (F# è naturale). La presenza di F naturale conferma il G misolidio — modo del blues e del rock." },
{ q: "Per armonizzare una melodia di flamenco, quale modo scegliere?", opts: ["Dorico (Im–IV)", "Frigio (Im–♭II)", "Misolidio (I–♭VII)", "Eolico (Im–♭VI–♭VII)"], a: 1, fb: "Il flamenco usa il modo frigio. La cadenza ♭II→Im (es. F→Em in E frigio) è il DNA armonico del flamenco — il colore scuro e mediterraneo deriva direttamente dalla 2a bemolle." },
{ q: "So What di Miles Davis (1959) è armonizzato con:", opts: ["Accordi frigi", "Accordi dorici (Dm7–G)", "Accordi misolidi", "Accordi lidi"], a: 1, fb: "So What è in D dorico. Miles Davis usa l'oscillazione Dm7 – G (Im – IV in dorico) — nessun V7→I. Il colore jazz-modale deriva da questo IV maggiore (G) in un contesto minore (Dm)." },
{ q: "Un'armonizzazione modale tipica:", opts: ["Contiene sempre V7→I", "Evita V7→I e usa l'accordo caratteristico del modo in modo ripetuto", "Usa solo accordi minori", "Modula verso la relativa maggiore"], a: 1, fb: "Un'armonizzazione modale si basa su: evitare V7→I (risoluzione tonale) e usare regolarmente l'accordo caratteristico (IV in dorico, ♭II in frigio, ecc.) che rivela il colore del modo." },
{ q: "Qual è l'accordo caratteristico del modo eolico?", opts: ["IV maggiore", "♭II maggiore", "♭VII maggiore (senza sensibile)", "II maggiore"], a: 2, fb: "♭VII maggiore distingue armonicamente l'eolico dal minore armonico. In A eolico: G maggiore (♭VII). L'assenza di sensibile (G invece di G#) è il marchio dell'eolico naturale." },
{ q: "Quale accordo è unico del modo lidio tra i modi maggiori?", opts: ["IV maggiore", "V dominante", "II maggiore", "♭VII maggiore"], a: 2, fb: "II maggiore esiste solo in lidio tra i modi della scala maggiore. In ionico e misolidio, II è minore. In lidio, il #4 rende II maggiore — è l'accordo che 'tradisce' il modo all'orecchio." },
{ q: "In modo frigio, quale accordo NON appartiene al modo?", opts: ["Im (Em in E frigio)", "♭II (F in E frigio)", "V7 (B7 in E frigio)", "♭VII (D in E frigio)"], a: 2, fb: "B7 contiene D# — la sensibile assente dal frigio (D naturale). Questo accordo è 'estraneo' al modo: rompe il colore frigio creando un'attrazione tonale verso Em." },
{ q: "Confrontando dorico ed eolico: qual è l'unica nota diversa?", opts: ["La 3a (maggiore vs minore)", "La 6a (maggiore in dorico, minore in eolico)", "La 5a (giusta vs diminuita)", "La 2a (maggiore vs bemolle)"], a: 1, fb: "Dorico ed eolico hanno gli stessi gradi tranne la 6a: il dorico ha una 6a maggiore (B in D dorico), l'eolico ha una 6a minore (Bb in D eolico). Questa sola nota cambia l'accordo IV da Gm a G maggiore — tutto il colore ne deriva." },
{ q: "Confrontando misolidio e ionico: qual è l'unica nota diversa?", opts: ["La 3a (maggiore vs minore)", "La 4a (giusta vs aumentata)", "La 7a (maggiore in ionico, minore in misolidio)", "La 5a (giusta vs diminuita)"], a: 2, fb: "Misolidio = ionico con ♭7. In G maggiore: F# diventa F naturale. Questa sola alterazione trasforma l'accordo VII da F#dim in F maggiore (♭VII) — e crea il colore blues/rock senza risoluzione." },
{ q: "Perché la musica modale sembra a volte 'fluttuare' o 'girare in tondo'?", opts: ["Perché i musicisti eseguono male le transizioni", "Perché non c'è risoluzione tonale obbligatoria — gli accordi oscillano piuttosto che progredire", "Perché il tempo è troppo lento", "Perché i modi non hanno tonica"], a: 1, fb: "La musica tonale crea direzione e arrivo (tensione → risoluzione). La musica modale crea sospensione, colore stabile — gli accordi oscillano attorno alla tonica senza chiamarla in modo imperativo. È voluto." },
{ q: "Le progressioni di accordi paralleli di Debussy sono tonali o modali?", opts: ["Tonali — tecnica classica", "Modali — gli accordi colorano il modo senza ruolo funzionale", "Atonali — senza tonalità", "Pentatoniche"], a: 1, fb: "Gli accordi paralleli di Debussy sono una tecnica modale: gli accordi non creano tensione funzionale (SD→D→T), si spostano come blocchi di colore — liberazione dai vincoli del contrappunto tonale." },
{ q: "In quale opera di Debussy l'influenza modale è più evidente?", opts: ["Clair de Lune (minore classico)", "La Cathédrale engloutie (modi medievali e accordi paralleli)", "Notturni di Chopin (romantico)", "Sinfonia di Franck"], a: 1, fb: "La Cathédrale engloutie (1910) utilizza modi medievali (lidio, mixolydiano) e accordi paralleli per evocare la cattedrale sommersa — l'esempio perfetto dell'armonia modale impressionista." },
];

const questionsPt: Question[] = [{ q: "Na harmonização modal, qual é o objetivo principal dos acordes?", opts: ["Criar tensão e resolução (SD→D→T)", "Manter e colorir o modo sem resolução obrigatória", "Sempre terminar em V7→I", "Usar os 7 acordes diatônicos de forma igual"], a: 1, fb: "No modal, os acordes devem preservar a cor do modo — não criar tensão tonal. A oscilação entre Im e um acorde característico é suficiente; uma resolução V7→I quebraria a identidade modal." },
{ q: "Por que se deve evitar V7→I em um contexto modal?", opts: ["V7 é muito dissonante", "V7 introduz a sensível ausente do modo, criando uma resolução tonal que apaga a cor modal", "V7 não existe na música modal", "V7 é reservado aos modos maiores"], a: 1, fb: "A sensível em V7 cria uma tensão irresistível em direção a I — esse é o motor tonal. No modal, queremos evitar essa atração para manter a cor flutuante do modo." },
{ q: "Qual é a diferença fundamental entre uma harmonização tonal e modal?", opts: ["A tonal usa mais acordes", "A tonal organiza os acordes em hierarquia tensão/resolução; a modal mantém uma cor estável", "A modal usa apenas acordes menores", "A tonal é mais moderna"], a: 1, fb: "Tonal = hierarquia funcional (T, SD, D) com resolução obrigatória. Modal = cor harmônica estável — os acordes oscilam em torno da tônica sem chamá-la de forma imperativa." },
{ q: "Como identificar o acorde característico de um modo para a harmonização?", opts: ["É sempre o acorde IV", "É o acorde construído sobre a nota distintiva do modo em relação à escala maior ou menor padrão", "É sempre o acorde ♭VII", "É o primeiro acorde diatônico"], a: 1, fb: "O acorde característico valoriza a nota distintiva do modo. No dórico: IV maior (6ª maior). No frígio: ♭II (2ª bemolizada). No lídio: II maior (#4). No mixolídio: ♭VII (7ª menor)." },
{ q: "Qual dessas progressões é modal (não tonal)?", opts: ["I – IV – V7 – I", "IIm – V7 – Imaj7", "Im – IV – Im – IV (dórico)", "I – VI – II – V"], a: 2, fb: "Im – IV – Im – IV (D dórico: Dm – G – Dm – G) é uma progressão modal — ela oscila sem resolução V7→I. As outras 3 são progressões tonais clássicas com um V7 ativo em direção a I." },
{ q: "O que mantém a cor modal em uma harmonização?", opts: ["Tocar sempre em menor", "Usar regularmente o acorde característico do modo e evitar V7→I", "Evitar toda dissonância", "Permanecer em um único acorde"], a: 1, fb: "A cor modal é mantida por dois elementos: o uso do acorde característico (que contém a nota distintiva) e a evitação de V7→I (que criaria uma resolução tonal)." },
{ q: "Como a música modal soa comparada à música tonal?", opts: ["A modal 'chega a algum lugar' como a tonal", "A modal 'permanece em algum lugar' — ela flutua e colore em vez de progredir", "A modal é sempre mais rápida", "A modal usa mais dissonâncias"], a: 1, fb: "A música tonal cria um sentimento de direção e chegada (tensão → resolução). A música modal cria um sentimento de suspensão, de cor estável — ela 'está' em algum lugar em vez de 'chegar' lá." },
{ q: "No modal, o que o acorde característico do modo substitui funcionalmente?", opts: ["O acorde de subdominante", "A dominante V7 — ele traz interesse harmônico sem criar resolução tonal", "A tônica", "O acorde de sexta napolitana"], a: 1, fb: "O acorde característico (IV no dórico, ♭II no frígio…) é o ponto de interesse harmônico do modo — evita a monotonia de um acorde único, mas sem a atração direcional do V7." },
{ q: "Qual progressão caracteriza a harmonização no modo dórico?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 1, fb: "Im – IV no dórico (ex. Dm – G em D dórico) é a progressão modal fundamental. IV é maior graças à 6ª maior — é a cor jazz-modal de So What de Miles Davis." },
{ q: "Em D dórico, qual acorde é IV e por que é característico?", opts: ["Gm — ele lembra o menor natural", "G maior — a 6ª maior (B natural) o torna maior", "G7 — ele cria tensão", "Gdim — ele é instável"], a: 1, fb: "Em D dórico: D E F G A B C. Sobre G: G B D = G maior. O B natural (6ª maior) torna esse acorde maior. Em D menor natural, IV seria Gm — é essa diferença que faz a cor dórica." },
{ q: "Qual acorde deve ser evitado na harmonização dórica?", opts: ["IV maior (G em D dórico)", "V7 (A7 em D dórico)", "♭III (F em D dórico)", "♭VII (C em D dórico)"], a: 1, fb: "A7 (V7 em D dórico) introduz C# — a sensível que o dórico não tem (C natural). Esse C# cria uma atração tonal em direção a Dm que quebra a cor modal e transforma o dórico em menor harmônico." },
{ q: "Qual peça de Miles Davis é o exemplo modal dórico por excelência?", opts: ["Kind of Blue — All Blues", "So What (D dórico)", "Round Midnight", "Autumn Leaves"], a: 1, fb: "So What (1959) está inteiramente em D dórico. Miles Davis e Bill Evans constroem a harmonia sobre Dm7–G (Im–IV), sem nunca pedir uma resolução tonal — é o arquétipo do jazz modal." },
{ q: "Na harmonização dórica, Im – IV cria:", opts: ["Uma tensão que pede resolução", "Uma oscilação colorida sem resolução", "Uma cadência perfeita", "Um movimento de subdominante para dominante"], a: 1, fb: "Im – IV no dórico (Dm – G) oscila entre dois acordes sem hierarquia funcional. Nenhuma tensão que peça resolução — é uma cor que se mantém, flutua, respira." },
{ q: "Em G dórico, qual acorde é IV?", opts: ["Cm (C menor)", "C maior", "Cdim", "C7"], a: 1, fb: "G dórico: G A Bb C D E F. Sobre C: C E G = C maior. A 6ª maior do dórico (E natural em vez de Eb) torna esse acorde IV maior — a marca harmônica do modo dórico." },
{ q: "A Bossa Nova usa frequentemente o dórico porque:", opts: ["O dórico é exclusivamente brasileiro", "A 6ª maior do dórico cria uma cor sofisticada meio sombria meio luminosa, perfeita para a saudade", "O dórico é o mais simples dos modos", "A Bossa Nova evita acordes maiores"], a: 1, fb: "A saudade brasileira — melancolia doce e luminosa — encontra no dórico sua expressão harmônica perfeita. A 6ª maior impede que IV seja sombrio (Gm) — ele permanece luminoso (G), criando o equilíbrio entre sombra e luz." },
{ q: "Qual é a cadência característica do modo frígio?", opts: ["V7 – I", "IV – I", "♭II – Im (cadência frígia)", "♭VII – I"], a: 2, fb: "A cadência frígia ♭II→Im (ex. F→Em em E frígio) é o DNA harmônico do flamenco. O movimento descendente por semitom cria uma tensão única, diferente de V7→I." },
{ q: "Em E frígio, qual acorde é ♭II?", opts: ["D maior", "F maior", "Eb maior", "B maior"], a: 1, fb: "E frígio: E F G A B C D. O ♭II é construído sobre F: F A C = F maior. A 2ª bemolizada do frígio (F em vez de F#) cria esse acorde muito característico." },
{ q: "Por que o movimento F→Em (em E frígio) é tão expressivo?", opts: ["F é uma quarta de Em", "É um movimento descendente por semitom — o menor de todos os intervalos", "F é a dominante de Em", "É um trítono"], a: 1, fb: "F→E é um semitom descendente — o intervalo menor e mais tenso. Esse movimento ♭II→Im cria uma atração poderosa por proximidade cromática, muito diferente da resolução tonal V7→I." },
{ q: "Qual gênero musical usa principalmente a cadência frígia?", opts: ["Blues americano", "Jazz modal", "Flamenco espanhol", "Gospel"], a: 2, fb: "O flamenco espanhol é fundado na cadência frígia ♭II→Im e suas variações. A cor sombria e mediterrânea do frígio — com sua 2ª bemolizada — é a identidade sonora da música andaluza." },
{ q: "Na harmonização frígia, qual acorde deve ser evitado?", opts: ["♭II (F em E frígio)", "Im (Em)", "V7 (B7 em E frígio)", "♭VII (D em E frígio)"], a: 2, fb: "B7 (V7 em E frígio) introduz D# — uma sensível estranha ao frígio (D natural). Esse D# cria uma resolução tonal em direção a Em, apagando a cor frígia." },
{ q: "Em A frígio, qual acorde é ♭II?", opts: ["G maior", "Bb maior", "B maior", "Ab maior"], a: 1, fb: "A frígio: A Bb C D E F G. O ♭II é construído sobre Bb: Bb D F = Bb maior. A 2ª bemolizada (Bb em vez de B) cria esse acorde característico do frígio." },
{ q: "A cor 'sombria e mediterrânea' está associada a qual modo?", opts: ["Dórico", "Lídio", "Frígio", "Eólio"], a: 2, fb: "O frígio é o modo do mediterrâneo — sua 2ª bemolizada e a cadência ♭II→Im criam uma cor sombria, intensa, dramática. É a identidade sonora do flamenco e da música espanhola." },
{ q: "Qual progressão caracteriza a harmonização no modo lídio?", opts: ["Im – ♭II – Im", "Im – IV – Im", "I – II – I", "I – ♭VII – IV – I"], a: 2, fb: "I – II no lídio (ex. F – G em F lídio) é a progressão característica. O II é maior graças ao #4 — um movimento de segunda ascendente maior–maior impossível na escala maior padrão (onde II é menor)." },
{ q: "Por que o acorde II é maior no modo lídio?", opts: ["Porque o lídio é um modo menor", "Porque o #4 (4ª aumentada) do lídio está no acorde II", "Porque II é sempre maior no modal", "Porque o lídio deriva do IVº grau"], a: 1, fb: "Em F lídio: F G A B C D E. Sobre G (II): G B D = G maior. O B natural (#4 do lídio) é a terça de G — torna o acorde II maior. Em F maior padrão, II seria Gm (com Bb)." },
{ q: "Qual compositor de músicas de filmes usa abundantemente o lídio para evocar o maravilhoso?", opts: ["Ennio Morricone", "John Williams", "Hans Zimmer", "Bernard Herrmann"], a: 1, fb: "John Williams usa o lídio em E.T., Superman e suas músicas mágicas. O #4 cria uma cor luminosa e onírica — a 4ª aumentada evita a estabilidade perfeita da escala maior e faz a música 'flutuar'." },
{ q: "Em F lídio, qual acorde deve ser evitado para preservar a cor?", opts: ["G maior (II)", "Bb (IV de F maior padrão)", "Am (IIIm)", "C (V)"], a: 1, fb: "Bb reintroduz exatamente a nota que o lídio substitui por B natural (#4). Tocar Bb apaga instantaneamente a cor lídia e faz soar uma escala maior padrão." },
{ q: "Em C lídio, qual acorde é II?", opts: ["Dm", "D maior", "Ddim", "D7"], a: 1, fb: "C lídio: C D E F# G A B. Sobre D: D F# A = D maior. O F# (#4 do lídio) é a terça de D — torna o acorde II maior e revela o modo ao ouvido." },
{ q: "A cor 'luminosa e onírica' está associada a qual modo?", opts: ["Eólio", "Frígio", "Mixolídio", "Lídio"], a: 3, fb: "O lídio com seu #4 cria uma cor luminosa e onírica. A 4ª aumentada evita a estabilidade perfeita da escala maior — ela flutua, ela brilha. É o modo do encantamento e da magia." },
{ q: "O tema principal dos Simpsons começa com um:", opts: ["Salto de frígio (♭2)", "Trítono ascendente lídio (fundamental para #4)", "Acorde de dominante", "Movimento eólio (♭VII)"], a: 1, fb: "O tema dos Simpsons começa com um salto ascendente até o #4 lídio — o trítono F→B em F lídio. É esse #4 ligeiramente estranho que cria aquela cor tão reconhecível." },
{ q: "Qual progressão é típica do modo mixolídio?", opts: ["Im – IV – Im", "Im – ♭VI – ♭VII – Im", "I – ♭VII – IV – I", "I – II – I"], a: 2, fb: "I – ♭VII – IV – I (ex. G – F – C – G em G mixolídio) é a progressão rock/blues por excelência. O ♭VII (F) cria um movimento de retorno sem resolução de sensível." },
{ q: "Em G mixolídio, qual acorde é ♭VII?", opts: ["F# maior", "F menor", "F maior", "Fdim"], a: 2, fb: "G mixolídio: G A B C D E F. O ♭VII é construído sobre F: F A C = F maior. A 7ª menor (F em vez de F#) torna esse acorde maior — é a marca harmônica do mixolídio." },
{ q: "Por que se evita V7 na harmonização mixolídia?", opts: ["V7 é simples demais", "V7 introduz a sensível (F# em G mixolídio) ausente do modo, criando uma resolução em direção a G", "V7 cria uma quinta paralela", "V7 muda o modo para lídio"], a: 1, fb: "Em G mixolídio, F é ♭7 (nota característica). D7 (V7) introduz F# — a sensível que não existe no modo. Esse F# cria uma tensão em direção a G (resolução tonal) que quebra a cor cíclica do mixolídio." },
{ q: "Qual estilo musical é harmonicamente baseado no modo mixolídio?", opts: ["Música barroca", "Flamenco espanhol", "Blues e rock", "Música romântica"], a: 2, fb: "O blues e o rock usam principalmente o mixolídio. O acorde I7 do blues (com 7ª menor) é o acorde do mixolídio. A progressão I7–IV7–V7 do blues é fundamentalmente mixolídia." },
{ q: "Norwegian Wood dos Beatles está em qual modo?", opts: ["Dórico", "Frígio", "Eólio", "Mixolídio"], a: 3, fb: "Norwegian Wood (1965) está em E mixolídio. A 7ª menor (D natural em vez de D#) na melodia e na harmonia dá essa cor modal característica — maior mas sem resolução." },
{ q: "Em D mixolídio, qual acorde é ♭VII?", opts: ["C# maior", "C menor", "C maior", "Cdim"], a: 2, fb: "D mixolídio: D E F# G A B C. Sobre C: C E G = C maior. A 7ª menor (C em vez de C#) é a nota característica do mixolídio — e esse acorde ♭VII maior é sua assinatura harmônica." },
{ q: "A cor 'enérgica e cíclica sem resolução' está associada a qual modo?", opts: ["Jônio", "Dórico", "Eólio", "Mixolídio"], a: 3, fb: "O mixolídio cria uma energia perpétua — a progressão I–♭VII–IV–I gira sem nunca realmente 'chegar'. A 7ª menor impede a resolução em direção a I mantendo a cor maior. É a essência do blues e do rock." },
{ q: "Qual progressão é típica do modo eólio?", opts: ["Im – IV – Im", "Im – ♭II – Im", "I – ♭VII – IV – I", "Im – ♭VI – ♭VII – Im"], a: 3, fb: "Im – ♭VI – ♭VII – Im (ex. Am – F – G – Am em A eólio) é a progressão menor natural mais difundida no pop e no rock. Ela oscila sem sensível, criando uma melancolia suave e natural." },
{ q: "Em A eólio, por que ♭VII é G maior?", opts: ["Porque G é a quinta de C", "Porque em A eólio (A B C D E F G), o acorde sobre G é G B D = G maior", "Porque G é sempre maior no menor", "Porque G é a tônica relativa"], a: 1, fb: "A eólio: A B C D E F G. Sobre G (♭VII): G B D = G maior. O B natural em G dá um acorde maior luminoso sobre o ♭VII — é ele que impede que a cor seja sombria demais." },
{ q: "Como o eólio se distingue harmonicamente do menor harmônico?", opts: ["O eólio tem uma terça maior", "O eólio não tem sensível — seu V é Vm (menor), não V7", "O eólio não tem o IVº grau", "O eólio usa o acorde napolitano"], a: 1, fb: "No eólio, V = Em (menor, sem sensível). No menor harmônico, V = E7 (com G# sensível). Essa sensível cria a resolução tonal. O eólio evita essa tensão — mais natural, menos direcionado." },
{ q: "A progressão Am – F – G – Am é tipicamente:", opts: ["Tonal (menor harmônico)", "Modal (eólio natural)", "Tonal (maior)", "Pentatônica"], a: 1, fb: "Am – F – G – Am é puramente eólia — sem E7 (V7). G (♭VII) e F (♭VI) são característicos do menor natural/eólio. É a progressão de House of the Rising Sun, Losing My Religion..." },
{ q: "Em A eólio, qual problema coloca E7 (V7)?", opts: ["Ele é grave demais", "Ele introduz G# — a sensível ausente do eólio — criando uma resolução tonal em direção a Am", "Ele cria uma quinta paralela", "Ele força a passagem para o lídio"], a: 1, fb: "E7 contém G# — a sensível que o eólio não tem (G natural). Esse G# pede imperativamente a resolução em direção a A, transformando o modo em menor harmônico e quebrando a melancolia natural do eólio." },
{ q: "Em E eólio, qual acorde é ♭VII?", opts: ["D# maior", "D menor", "D maior", "Ddim"], a: 2, fb: "E eólio: E F# G A B C D. Sobre D: D F# A = D maior. O D natural (♭7) torna o acorde ♭VII maior — sua presença caracteriza harmonicamente o modo eólio e distingue sua cor do menor harmônico." },
{ q: "Stairway to Heaven do Led Zeppelin usa principalmente:", opts: ["O modo lídio", "O modo mixolídio", "O modo eólio (menor natural)", "O modo frígio"], a: 2, fb: "Stairway to Heaven se apoia em A menor natural (A eólio) — a progressão Am – G – F característica. A melancolia introspectiva do menor natural sem sensível é tipicamente eólia." },
{ q: "Um acorde IV maior em um contexto menor indica provavelmente qual modo?", opts: ["Menor harmônico", "Modo dórico", "Modo frígio", "Modo lócrio"], a: 1, fb: "IV maior em um contexto menor é a assinatura harmônica do dórico. No menor natural (eólio), IV seria menor. A presença de um IV maior (ex. G em D menor) sinaliza a 6ª maior dórica." },
{ q: "Um acorde ♭II em um contexto menor indica provavelmente qual modo?", opts: ["Modo dórico", "Menor harmônico", "Modo frígio", "Modo eólio"], a: 2, fb: "♭II em um contexto menor é a assinatura do frígio. O acorde construído sobre a 2ª bemolizada (ex. F em E frígio) é único nesse modo — nenhum outro modo menor o possui naturalmente." },
{ q: "Um acorde ♭VII maior em um contexto maior indica provavelmente qual modo?", opts: ["Modo lídio", "Modo jônio", "Modo mixolídio", "Modo dórico"], a: 2, fb: "♭VII maior em um contexto maior é a assinatura do mixolídio. Na escala maior padrão, ♭VII não existe (o VIIº grau é diminuto). A presença de ♭VII maior (ex. F em G maior) sinaliza a 7ª menor mixolídia." },
{ q: "Qual é a diferença entre Im–IV (dórico) e Im–Vm (eólio)?", opts: ["Im–IV é dinamicamente mais forte", "Im–IV usa IV maior (dórico, 6ª maior); Im–Vm usa V menor (eólio, 6ª menor)", "Im–Vm é uma cadência perfeita", "Não há diferença"], a: 1, fb: "A diferença é a 6ª do modo. Dórico: 6ª maior → IV é maior (G em D dórico). Eólio: 6ª menor → Vm é menor (Em em A eólio). Esses dois acordes criam uma cor radicalmente diferente." },
{ q: "Qual progressão é a mais tonal entre estas opções?", opts: ["Dm – G – Dm (Im–IV dórico)", "Em – F – Em (♭II frígio)", "Am – Dm – E7 – Am", "G – F – C – G (mixolídio)"], a: 2, fb: "Am – Dm – E7 – Am contém E7 (V7) que introduz G# (sensível) e resolve tonalmente em direção a Am — é menor harmônico, não modal. As outras 3 evitam V7→I e mantêm uma cor modal." },
{ q: "Para harmonizar uma melodia rock com um riff G – F – C – G, o modo é:", opts: ["Jônio (G maior)", "Dórico", "Mixolídio (G mixolídio)", "Lídio"], a: 2, fb: "G – F – C – G = I – ♭VII – IV – I em G mixolídio. O F (♭VII) não existe em G maior padrão (F# é natural lá). A presença de F natural confirma o G mixolídio — modo do blues e do rock." },
{ q: "Para harmonizar uma melodia de flamenco, qual modo escolher?", opts: ["Dórico (Im–IV)", "Frígio (Im–♭II)", "Mixolídio (I–♭VII)", "Eólio (Im–♭VI–♭VII)"], a: 1, fb: "O flamenco usa o modo frígio. A cadência ♭II→Im (ex. F→Em em E frígio) é o DNA harmônico do flamenco — a cor sombria e mediterrânea vem diretamente da 2ª bemolizada." },
{ q: "So What de Miles Davis (1959) é harmonizado com:", opts: ["Acordes frígios", "Acordes dóricos (Dm7–G)", "Acordes mixolídios", "Acordes lídios"], a: 1, fb: "So What está em D dórico. Miles Davis usa a oscilação Dm7 – G (Im – IV no dórico) — sem V7→I. A cor jazz-modal vem desse IV maior (G) em um contexto menor (Dm)." },
{ q: "Uma harmonização modal típica:", opts: ["Contém sempre V7→I", "Evita V7→I e usa o acorde característico do modo de forma repetida", "Usa apenas acordes menores", "Modula para a relativa maior"], a: 1, fb: "Uma harmonização modal se baseia em: evitar V7→I (resolução tonal) e usar regularmente o acorde característico (IV no dórico, ♭II no frígio, etc.) que revela a cor do modo." },
{ q: "Qual é o acorde característico do modo eólio?", opts: ["IV maior", "♭II maior", "♭VII maior (sem sensível)", "II maior"], a: 2, fb: "♭VII maior distingue harmonicamente o eólio do menor harmônico. Em A eólio: G maior (♭VII). A ausência de sensível (G em vez de G#) é a marca do eólio natural." },
{ q: "Qual acorde é único do modo lídio entre os modos maiores?", opts: ["IV maior", "V dominante", "II maior", "♭VII maior"], a: 2, fb: "II maior só existe no lídio entre os modos da escala maior. No jônio e no mixolídio, II é menor. No lídio, o #4 torna II maior — é o acorde que 'trai' o modo ao ouvido." },
{ q: "No modo frígio, qual acorde NÃO pertence ao modo?", opts: ["Im (Em em E frígio)", "♭II (F em E frígio)", "V7 (B7 em E frígio)", "♭VII (D em E frígio)"], a: 2, fb: "B7 contém D# — a sensível ausente do frígio (D natural). Esse acorde é 'estranho' ao modo: ele quebra a cor frígia criando uma atração tonal em direção a Em." },
{ q: "Comparando dórico e eólio: qual é a única nota diferente?", opts: ["A 3ª (maior vs menor)", "A 6ª (maior no dórico, menor no eólio)", "A 5ª (justa vs diminuta)", "A 2ª (maior vs bemolizada)"], a: 1, fb: "Dórico e eólio têm os mesmos graus exceto a 6ª: o dórico tem 6ª maior (B em D dórico), o eólio tem 6ª menor (Bb em D eólio). Essa única nota muda o acorde IV de Gm para G maior — toda a cor decorre disso." },
{ q: "Comparando mixolídio e jônio: qual é a única nota diferente?", opts: ["A 3ª (maior vs menor)", "A 4ª (justa vs aumentada)", "A 7ª (maior no jônio, menor no mixolídio)", "A 5ª (justa vs diminuta)"], a: 2, fb: "Mixolídio = jônio com ♭7. Em G maior: F# torna-se F natural. Essa única alteração transforma o acorde VII de F#dim em F maior (♭VII) — e cria a cor blues/rock sem resolução." },
{ q: "Por que a música modal parece às vezes 'flutuar' ou 'girar em círculos'?", opts: ["Porque os músicos tocam mal as transições", "Porque não há resolução tonal obrigatória — os acordes oscilam em vez de progredir", "Porque o andamento é lento demais", "Porque os modos não têm tônica"], a: 1, fb: "A música tonal cria direção e chegada (tensão → resolução). A música modal cria suspensão, cor estável — os acordes oscilam em torno da tônica sem chamá-la de forma imperativa. É intencional." },
{ q: "As progressões de acordes paralelos de Debussy são tonais ou modais?", opts: ["Tonais — técnica clássica", "Modais — os acordes colorem o modo sem papel funcional", "Atonais — sem tonalidade", "Pentatônicas"], a: 1, fb: "Os acordes paralelos de Debussy são uma técnica modal: os acordes não criam tensão funcional (SD→D→T), eles se deslocam como blocos de cor — libertação das restrições do contraponto tonal." },
{ q: "Em qual obra de Debussy a influência modal é mais evidente?", opts: ["Clair de Lune (menor clássico)", "La Cathédrale engloutie (modos medievais e acordes paralelos)", "Nocturnos de Chopin (romântico)", "Sinfonia de Franck"], a: 1, fb: "La Cathédrale engloutie (1910) usa modos medievais (lídio, mixolídio) e acordes paralelos para evocar a catedral sob as águas — o exemplo perfeito da harmonia modal impressionista." },
];

